editmore_vertUser<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Dopamine Lab v25: The Genesis Engine (Fully Integrated)</title>
    <link rel="preconnect" href="https://fonts.googleapis.com">
    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;700&display=swap" rel="stylesheet">
    <style>
        :root {
            --panel-bg: rgba(20, 20, 30, 0.95);
            --accent-color: #00aaff;
            --accent-hover: #33bbff;
            --record-color: #ff4136;
            --text-color: #e0e0e0;
            --sequencer-bg: rgba(10, 10, 20, 0.95);
            --step-off: rgba(255, 255, 255, 0.1);
            --step-on: var(--accent-color);
            --step-active: white;
            --step-visual: #ff00ff;
            --step-plock: #ff9900;
            --border-color: rgba(255, 255, 255, 0.2);
            --font-main: 'Inter', sans-serif;
            --controls-width: 360px;
            --piano-roll-height: 250px;
        }

        /* --- Base & Scrollbar --- */
        *, *::before, *::after { box-sizing: border-box; }
        body {
            margin: 0;
            background-color: #050508;
            color: var(--text-color);
            font-family: var(--font-main);
            -webkit-font-smoothing: antialiased;
            -moz-osx-font-smoothing: grayscale;
            overflow: hidden;
        }
        *::-webkit-scrollbar { width: 8px; }
        *::-webkit-scrollbar-track { background: rgba(0,0,0,0.2); }
        *::-webkit-scrollbar-thumb { background-color: var(--accent-color); border-radius: 20px; }

        /* --- Layout --- */
        #container { position: fixed; inset: 0; z-index: 1; }

        #main-controls-panel {
            position: fixed; top: 0; right: 0; bottom: 0;
            width: var(--controls-width); background: var(--panel-bg);
            backdrop-filter: blur(15px); -webkit-backdrop-filter: blur(15px);
            border-left: 1px solid var(--border-color);
            z-index: 20; display: flex; flex-direction: column;
        }

        #sequencer-dock {
            position: fixed; bottom: 0; left: 0;
            right: var(--controls-width);
            background: var(--sequencer-bg);
            border-top: 1px solid var(--border-color);
            z-index: 15; padding: 15px; overflow-x: auto;
            transition: bottom 0.3s ease;
        }
        #sequencer-dock.piano-open { bottom: var(--piano-roll-height); }

        /* --- Piano Roll --- */
        #piano-roll-dock {
            position: fixed; bottom: 0; left: 0; right: var(--controls-width);
            height: var(--piano-roll-height); background: #080810;
            border-top: 1px solid var(--border-color); z-index: 18;
            display: flex; transform: translateY(100%); transition: transform 0.3s ease;
        }
        #piano-roll-dock.open { transform: translateY(0); }
        #piano-keyboard { flex-shrink: 0; width: 60px; background: #111; overflow-y: scroll; scrollbar-width: none; }
        #piano-keyboard::-webkit-scrollbar { display: none; }
        .piano-key { height: 12px; border: 1px solid #333; font-size: 0.6em; display: flex; align-items: center; justify-content: center; cursor: pointer; }
        .piano-key.black { background: #444; color: #aaa; margin: -6px 0 -6px 20px; height: 12px; position: relative; z-index: 1; }
        .piano-key.white { background: #ddd; color: #222; }
        #piano-grid-wrapper { flex-grow: 1; overflow-x: auto; }
        #piano-grid { display: grid; grid-template-columns: repeat(var(--num-steps, 16), 40px); grid-auto-rows: 12px; }
        .piano-cell { background-color: rgba(255,255,255,0.02); border: 1px solid #222; cursor: pointer; }
        .piano-cell:hover { background-color: rgba(255,255,255,0.1); }
        .piano-cell.note-on { background-color: var(--accent-color); border-color: var(--accent-hover); }

        /* --- Tabs & Main Panel --- */
        .tabs { display: grid; grid-template-columns: repeat(auto-fit, minmax(50px, 1fr)); flex-shrink: 0; border-bottom: 1px solid var(--border-color); }
        .tab-button { padding: 12px 5px; background: transparent; border: none; color: var(--text-color); cursor: pointer; font-weight: bold; font-size: 0.75em; transition: all 0.2s; border-bottom: 3px solid transparent; }
        .tab-button:hover { background-color: rgba(255,255,255,0.1); }
        .tab-button.active { color: var(--accent-color); border-bottom-color: var(--accent-color); }
        .tab-content-wrapper { flex-grow: 1; overflow-y: auto; }
        .tab-content { display: none; padding: 15px; }
        .tab-content.active { display: block; }

        /* --- UI Components --- */
        h1, h2, h4 { color: var(--accent-color); text-align: center; margin: 0 0 15px 0; text-transform: uppercase; letter-spacing: 1px; }
        h4 { margin: 15px 0 10px; text-align: left; }
        fieldset, details { border: 1px solid #444; border-radius: 8px; padding: 10px; margin-bottom: 15px; }
        legend, summary { font-weight: bold; color: var(--accent-color); cursor: pointer; }
        label { display: block; margin: 10px 0 5px; font-size: 0.85em; }
        input[type="range"] { -webkit-appearance: none; appearance: none; width: 100%; height: 5px; background: #333; border-radius: 5px; outline: none; }
        input[type="range"]::-webkit-slider-thumb { -webkit-appearance: none; appearance: none; width: 15px; height: 15px; background: var(--accent-color); cursor: pointer; border-radius: 50%; }
        input[type="range"]::-moz-range-thumb { width: 15px; height: 15px; background: var(--accent-color); cursor: pointer; border-radius: 50%; }
        select, textarea, input[type="text"], input[type="file"] { width: 100%; background: #333; color: var(--text-color); border: 1px solid #555; padding: 8px; border-radius: 5px; }
        textarea { resize: vertical; min-height: 60px; }
        button { background-color: var(--accent-color); color: #000; border: none; padding: 10px 15px; border-radius: 5px; cursor: pointer; width: 100%; font-weight: bold; margin-top: 10px; transition: background-color 0.2s, transform 0.1s; }
        button:hover { background-color: var(--accent-hover); }
        button:active { transform: scale(0.98); }
        button:disabled { background-color: #555; cursor: not-allowed; }
        button.recording { background-color: var(--record-color); color: white; }
        .button-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; }
        .loader { border: 4px solid #f3f3f3; border-radius: 50%; border-top: 4px solid var(--accent-color); width: 20px; height: 20px; animation: spin 2s linear infinite; display: none; margin: 10px auto; }
        @keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }

        /* --- Sequencer & Tracks --- */
        .track { display: flex; align-items: center; gap: 8px; margin-bottom: 8px; }
        .track-header { width: 120px; display: flex; align-items: center; gap: 5px; flex-shrink: 0; }
        .track-label { font-size: 0.9em; font-weight: bold; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; flex-grow: 1; cursor: pointer; }
        .track-label:hover { text-decoration: underline; }
        .clear-track-btn { all: unset; box-sizing: border-box; cursor: pointer; font-size: 0.8em; color: #888; border: 1px solid #555; border-radius: 4px; padding: 2px 5px; line-height: 1; transition: all 0.2s; }
        .clear-track-btn:hover { background: var(--record-color); color: white; border-color: var(--record-color); }
        .steps { display: grid; grid-template-columns: repeat(var(--num-steps, 16), 1fr); gap: 5px; flex-grow: 1;}
        .step { width: 100%; padding-bottom: 100%; height: 0; background: var(--step-off); border-radius: 5px; cursor: pointer; transition: all 0.15s ease; position: relative; border: 1px solid transparent; }
        .step-content { position: absolute; inset: 0; display: flex; align-items: center; justify-content: center; font-size: 0.7em; }
        .step:hover { background-color: rgba(255, 255, 255, 0.2); }
        .step.on { background-color: var(--step-on); }
        .step.visual { background-color: var(--step-visual); }
        .step.active { box-shadow: 0 0 10px var(--step-active), inset 0 0 5px rgba(0,0,0,0.5); transform: scale(1.1); }
        .step.has-plock { border: 1px solid var(--step-plock); }
        .step.drag-over { border: 2px dashed white; }

        /* --- Arranger --- */
        #pattern-clips-container { display: flex; flex-wrap: wrap; gap: 8px; margin-bottom: 10px; }
        .pattern-clip { background: #333; padding: 8px 12px; border-radius: 5px; cursor: grab; transition: all 0.2s; border: 1px solid #555; }
        .pattern-clip.active-pattern { background: var(--accent-color); color: black; font-weight: bold; border-color: var(--accent-hover); }
        #master-track-container { display: grid; grid-template-columns: repeat(8, 1fr); gap: 5px; }
        .master-track-slot { background: var(--step-off); height: 35px; border-radius: 4px; font-size: 0.7em; display: flex; align-items: center; justify-content: center; overflow: hidden; white-space: nowrap; }

        /* --- Modals --- */
        .modal-overlay { display: none; position: fixed; inset: 0; background: rgba(0,0,0,0.7); backdrop-filter: blur(5px); z-index: 199; }
        .modal { display: none; position: fixed; top: 50%; left: 50%; transform: translate(-50%, -50%); background: var(--panel-bg); padding: 20px; border-radius: 10px; z-index: 200; box-shadow: 0 10px 30px rgba(0,0,0,0.5); width: 90%; max-width: 500px; border: 1px solid var(--border-color); }
        .modal.open { display: block; } .modal-overlay.open { display: block; }
        .modal h3 { margin-top: 0; color: var(--accent-color); }
        #note-grid { display: grid; grid-template-columns: repeat(12, 1fr); gap: 5px; max-height: 300px; overflow-y: auto; margin-bottom: 15px; }
        #note-grid button { margin: 0; padding: 8px 4px; font-size: 0.8em; }

        /* --- Responsive --- */
        #mobile-controls-toggle { display: none; }
        @media (max-width: 768px) {
            :root { --controls-width: 100%; --piano-roll-height: 200px; }
            #main-controls-panel { transform: translateX(100%); transition: transform 0.3s ease-in-out; position: fixed; height: 100%; top: 0; right: 0; }
            #main-controls-panel.open { transform: translateX(0); }
            #sequencer-dock, #piano-roll-dock { right: 0; }
            #mobile-controls-toggle { display: block; position: fixed; bottom: 20px; right: 20px; z-index: 50; width: 50px; height: 50px; border-radius: 50%; font-size: 1.5em; padding: 0; }
        }
    </style>
</head>
<body>
    <div id="container"></div>

    <div id="main-controls-panel" class="ui-element">
        <div class="tabs">
            <button class="tab-button active" data-tab="master-tab">Master</button>
            <button class="tab-button" data-tab="arranger-tab">Arranger</button>
            <button class="tab-button" data-tab="ai-tab">✨ AI</button>
            <button class="tab-button" data-tab="synths-tab">Synths</button>
            <button class="tab-button" data-tab="visuals-tab">Visuals</button>
            <button class="tab-button" data-tab="mod-tab">Mod</button>
            <button class="tab-button" data-tab="sampling-tab">Sampling</button>
        </div>

        <div class="tab-content-wrapper">
            <div id="master-tab" class="tab-content active">
                <h1>Master</h1>
                <fieldset><legend>Transport</legend>
                    <button id="play-toggle" disabled>Loading Audio...</button>
                    <label for="bpm-slider">BPM: <span id="bpm-value">120</span></label>
                    <input type="range" id="bpm-slider" min="40" max="240" value="120">
                    <label for="loop-length">Loop Length (Steps)</label>
                    <select id="loop-length"><option value="8">8</option><option value="16" selected>16</option><option value="32">32</option><option value="64">64</option></select>
                </fieldset>
                <fieldset><legend>Project</legend>
                     <div class="button-grid">
                         <button id="save-project-btn">Save Project</button>
                         <button id="load-project-btn">Load Project</button>
                         <input type="file" id="project-file-input" accept=".json" style="display:none;">
                    </div>
                </fieldset>
                <details><summary>Randomize</summary>
                    <div class="randomize-options">
                        <label><input type="checkbox" id="rand-patterns" checked> Patterns</label>
                        <label><input type="checkbox" id="rand-synths" checked> Synths</label>
                        <label><input type="checkbox" id="rand-visuals" checked> Visuals</label>
                    </div>
                    <button id="randomize-all-btn">Randomize All</button>
                </details>
                <fieldset><legend>Recording</legend>
                    <div class="button-grid">
                        <button id="record-btn">Record Video</button>
                        <button id="record-audio-btn">Record Audio</button>
                    </div>
                </fieldset>
                <fieldset><legend>MIDI</legend>
                    <label for="midi-input-select">MIDI Input Device</label>
                    <select id="midi-input-select"><option>No devices found</option></select>
                </fieldset>
            </div>

            <div id="arranger-tab" class="tab-content">
                <h2>Arranger</h2>
                <button id="create-pattern-btn">Create New Pattern</button>
                <h4>Pattern Clips</h4> <div id="pattern-clips-container"></div>
                <h4>Master Track</h4> <div id="master-track-container"></div>
            </div>

            <div id="ai-tab" class="tab-content">
                <h2>✨ AI Tools</h2>
                 <fieldset><legend>API Key</legend>
                    <p style="font-size: 0.8em; margin-top: 0;">An API key is required for AI features. It will be stored in session storage.</p>
                    <button id="manage-api-key-btn">Manage API Key</button>
                </fieldset>
                <fieldset><legend>AI Arranger</legend>
                    <label for="ai-arrange-prompt">Describe a song structure:</label>
                    <textarea id="ai-arrange-prompt" placeholder="e.g., quiet intro for 4 bars, add drums, build for 8 bars, then a drop..."></textarea>
                    <button id="generate-arrangement-btn">Generate Arrangement</button>
                    <div id="ai-arrange-loader" class="loader"></div>
                </fieldset>
                <fieldset><legend>AI Sound Designer</legend>
                    <p>Describe a sound, and the AI will try to create it on the target synth.</p>
                    <label for="ai-synth-target">Target Synth:</label>
                    <select id="ai-synth-target"></select>
                    <label for="ai-sound-prompt">Describe the sound:</label>
                    <textarea id="ai-sound-prompt" placeholder="e.g., a deep wobbly bass, a bright ethereal pad, a sharp percussive pluck..."></textarea>
                    <button id="generate-sound-btn">Generate Sound</button>
                    <div id="ai-sound-loader" class="loader"></div>
                </fieldset>
                 <fieldset><legend>AI Image Generator</legend>
                    <label for="ai-image-prompt">Describe an image for the visual background:</label>
                    <textarea id="ai-image-prompt" placeholder="e.g., a nebula made of liquid chrome"></textarea>
                    <button id="generate-image-btn">Generate Image</button>
                    <div id="ai-image-loader" class="loader"></div>
                </fieldset>
            </div>

            <div id="synths-tab" class="tab-content">
                <h2>Synths</h2>
                <fieldset><legend>Add New Track</legend>
                    <label for="add-track-type">Instrument Type</label>
                    <select id="add-track-type">
                        <option value="FMSynth">FM Synth</option>
                        <option value="AMSynth">AM Synth</option>
                        <option value="PluckSynth">Pluck Synth</option>
                    </select>
                    <button id="add-track-btn">✨ Add Track & Name It</button>
                </fieldset>
                <button id="randomize-synths-btn">Randomize All Synths</button>
                <div id="synth-controls-container"></div>
            </div>

            <div id="visuals-tab" class="tab-content">
                <h2>Visuals</h2>
                <fieldset><legend>✨ 3D Genesis Engine</legend>
                    <label for="camera-mode">Camera Mode</label>
                    <select id="camera-mode"><option value="orbit">Orbit</option><option value="fly">Fly</option></select>
                    <button id="add-object-btn">Add 3D Object</button>
                    <button id="reset-visuals-btn">Reset Scene</button>
                </fieldset>
                <details open><summary>2D Shader Background</summary>
                     <h4>Layer 1: Generative Shader</h4>
                     <label for="pattern">Shader Pattern</label> <select id="pattern"></select>
                     <label for="complexity">Complexity</label> <input type="range" id="complexity" min="0" max="1" value="0.6" step="0.01">
                     <label for="intensity">Intensity</label> <input type="range" id="intensity" min="0" max="2" value="1" step="0.01">
                     <button id="randomize-visuals-btn">Randomize 2D</button>
                     <hr style="border-color: #444; margin: 15px 0;">
                     <h4>Layer 2: Image Texture</h4>
                     <label for="layer2-opacity">Opacity</label>
                     <input type="range" id="layer2-opacity" min="0" max="1" value="0.0" step="0.01">
                     <label for="layer2-blend-mode">Blend Mode</label>
                     <select id="layer2-blend-mode">
                         <option value="0">Normal</option>
                         <option value="1">Add</option>
                         <option value="2">Screen</option>
                         <option value="3">Multiply</option>
                     </select>
                </details>
            </div>

            <div id="mod-tab" class="tab-content">
                <h2>Modulation Matrix</h2>
                <div id="mod-matrix-container"></div>
            </div>

            <div id="sampling-tab" class="tab-content">
                <h2>Sampling</h2>
                <fieldset>
                    <legend>Granular Sampler</legend>
                    <p>Load an audio file to use in the Granular track.</p>
                    <input type="file" id="granular-sample-input" accept="audio/*">
                </fieldset>
                <fieldset>
                    <legend>Mic Sampling</legend>
                    <button id="record-sample-btn">Record Sample</button>
                    <button id="add-sample-track-btn" disabled>Add Sample Track</button>
                </fieldset>
            </div>
        </div>

        <div id="kaoss-pad-container" style="padding: 15px; border-top: 1px solid var(--border-color); flex-shrink: 0;">
             <div id="kaoss-pad-wrapper" style="width: 150px; height: 150px; margin: 0 auto; position: relative;">
                <div id="kaoss-pad" style="width: 100%; height: 100%; background: var(--step-off); border-radius: 5px; cursor: crosshair;">
                    <div id="kaoss-indicator" style="position: absolute; width: 15px; height: 15px; background: white; border-radius: 50%; top: 50%; left: 50%; transform: translate(-50%, -50%); opacity: 0; pointer-events: none; transition: opacity 0.2s;"></div>
                </div>
            </div>
        </div>
    </div>

    <div id="sequencer-dock" class="ui-element">
        <div id="sequencer-container"></div>
    </div>

    <div id="piano-roll-dock" class="ui-element">
        <div id="piano-keyboard"></div>
        <div id="piano-grid-wrapper">
            <div id="piano-grid"></div>
        </div>
    </div>

    <button id="mobile-controls-toggle" class="ui-element">☰</button>

    <div class="modal-overlay"></div>
    <div id="welcome-modal" class="modal ui-element">
        <h3>Welcome to Dopamine Lab v25</h3>
        <p>This is the <b>Genesis Engine</b>, a fully integrated professional-grade generative audio-visual instrument.</p>
        <ul>
            <li>✨ Use the <b>AI Tab</b> to generate arrangements, sounds, track names, and image textures.</li>
            <li>🎹 Click a track name in the sequencer to open the new <b>Piano Roll</b> for melodic editing.</li>
            <li>🖼️ The <b>Visuals Tab</b> now controls both the 3D scene and a layered 2D shader background.</li>
            <li>🎤 The <b>Sampling Tab</b> allows for mic recording and granular synthesis.</li>
            <li>ARR Drag patterns from the <b>Arranger Tab</b> to the Master Track to build your song.</li>
        </ul>
        <button id="start-audio-btn">Start Audio Engine</button>
    </div>
    <div id="note-modal" class="modal ui-element">
        <h3>Select Note</h3>
        <div id="note-grid"></div>
        <button class="close-modal-btn">Close</button>
    </div>
    <div id="plock-modal" class="modal ui-element">
        <h3>Parameter Lock</h3>
        <label for="plock-param-select">Parameter</label>
        <select id="plock-param-select"></select>
        <label for="plock-value-slider">Value</label>
        <input type="range" id="plock-value-slider" min="0" max="1" step="0.01">
        <div class="button-grid">
            <button id="plock-save-btn">Save</button>
            <button id="plock-clear-btn">Clear Lock</button>
        </div>
    </div>
    <div id="message-modal" class="modal ui-element">
         <h3 id="message-title"></h3><p id="message-text"></p>
         <button class="close-modal-btn">OK</button>
    </div>
    <div id="api-key-modal" class="modal ui-element">
        <h3>Enter Gemini API Key</h3>
        <p>To use the AI features, please enter your Google AI Studio API key. It will only be stored for your current session.</p>
        <input type="text" id="api-key-input" placeholder="Enter your API key here">
        <button id="save-api-key-btn">Save Key</button>
    </div>

    <script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>
    <script src="https://cdn.jsdelivr.net/npm/three@0.128.0/examples/js/controls/OrbitControls.js"></script>
    <script src="https://cdnjs.cloudflare.com/ajax/libs/tone/14.7.77/Tone.js"></script>

    <script type="x-shader/x-vertex" id="vertexShader">
        varying vec2 vUv;
        void main() {
            vUv = uv;
            gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
        }
    </script>

    <script type="x-shader/x-fragment" id="generativeFragmentShader">
        uniform vec2 u_resolution;
        uniform float u_time;
        uniform float u_complexity;
        uniform float u_intensity;
        uniform int u_pattern;
        uniform sampler2D u_feedback_texture;
        varying vec2 vUv;
        #define PI 3.14159265359

        float random(vec2 st) { return fract(sin(dot(st.xy, vec2(12.9898, 78.233))) * 43758.5453123); }
        float noise(vec2 st) { vec2 i=floor(st); vec2 f=fract(st); vec2 u=f*f*(3.-2.*f); return mix(mix(random(i),random(i+vec2(1,0)),u.x),mix(random(i+vec2(0,1)),random(i+vec2(1,1)),u.x),u.y); }
        mat2 rotate(float a) { float s=sin(a); float c=cos(a); return mat2(c,-s,s,c); }

        vec3 hsv2rgb(vec3 c) {
            vec4 K = vec4(1.0, 2.0 / 3.0, 1.0 / 3.0, 3.0);
            vec3 p = abs(fract(c.xxx + K.xyz) * 6.0 - K.www);
            return c.z * mix(K.xxx, clamp(p - K.xxx, 0.0, 1.0), c.y);
        }

        vec3 getColor(float value) {
            float hue = fract(u_time * 0.05 + value * 0.1);
            float sat = 0.8;
            float val = clamp(value, 0.0, 1.0);
            return hsv2rgb(vec3(hue, sat, val));
        }

        vec3 pattern_fluid(vec2 st) {
            float v = 0.0; float a = 0.5; st *= 2.0 + u_complexity * 2.0;
            for (int i = 0; i < 7; i++) { v += a * noise(st); st *= 2.0; a *= 0.5; }
            vec2 q = vec2(v);
            vec2 r = vec2(noise(st + q * u_intensity + u_time * 0.1), noise(st + q * u_intensity + u_time * 0.1));
            float f = noise(st + r);
            return getColor(f);
        }

        float sdBox(vec3 p, vec3 b) { vec3 q = abs(p) - b; return length(max(q,0.0)) + min(max(q.x,max(q.y,q.z)),0.0); }
        vec3 pattern_geo(vec2 st) {
            vec3 ro = vec3(0, 0, -5.0); vec3 rd = normalize(vec3(st - 0.5, 1.0)); float d = 0.0;
            for (int i = 0; i < 64; i++) {
                vec3 p = ro + rd * d;
                p.xy *= rotate(u_time * 0.2 + u_complexity * 2.0); p.xz *= rotate(u_time * 0.1);
                float s = 0.5 + 0.5 * sin(u_time * 0.5); float ds = sdBox(p, vec3(s));
                d += ds * 0.5; if (d > 100.0 || ds < 0.001) break;
            }
            float glow = 1.0 / (d * d * 5.0 + 0.1);
            return getColor(glow * u_intensity);
        }

        vec3 pattern_rd(vec2 st) {
            vec2 texel = 1.0 / u_resolution.xy;
            vec4 n=texture2D(u_feedback_texture,st+vec2(0,1)*texel), e=texture2D(u_feedback_texture,st+vec2(1,0)*texel), s=texture2D(u_feedback_texture,st+vec2(0,-1)*texel), w=texture2D(u_feedback_texture,st+vec2(-1,0)*texel), c=texture2D(u_feedback_texture,st);
            vec4 lap = n + e + s + w - 4.0 * c;
            float feed = mix(0.054, 0.06, u_complexity); float kill = mix(0.06, 0.063, 0.5 + u_intensity * 0.5);
            float A = c.x + (1.0 * lap.x - c.x * c.y * c.y + feed * (1.0 - c.x)) * 1.0;
            float B = c.y + (0.5 * lap.y + c.x * c.y * c.y - (kill + feed) * c.y) * 1.0;
            if (random(st + u_time) > 0.999) B = 1.0;
            return getColor((A - B) * 2.0);
        }

        vec3 pattern_kaleido(vec2 st) {
            vec2 p = st - 0.5;
            float r = length(p);
            float a = atan(p.y, p.x);
            float sides = floor(2.0 + u_complexity * 10.0);
            a = mod(a, PI * 2.0 / sides);
            a = abs(a - PI / sides);
            p = r * vec2(cos(a), sin(a));
            p += 0.5;
            vec4 feedback = texture2D(u_feedback_texture, p);
            feedback.rgb *= 0.97 + u_intensity * 0.02;
            return getColor(length(feedback.rgb));
        }

        void main() {
            vec2 st = vUv;
            st.x *= u_resolution.x / u_resolution.y;
            vec3 color = vec3(0.0);
            if (u_pattern == 0)      color = pattern_fluid(st);
            else if (u_pattern == 1) color = pattern_geo(st);
            else if (u_pattern == 2) color = pattern_rd(st);
            else if (u_pattern == 3) color = pattern_kaleido(st);
            gl_FragColor = vec4(color, 1.0);
        }
    </script>

     <script type="x-shader/x-fragment" id="compositeFragmentShader">
        varying vec2 vUv;
        uniform sampler2D u_layer1_texture;
        uniform sampler2D u_image_texture;
        uniform float u_layer2_opacity;
        uniform int u_layer2_blend_mode;

        vec3 blendAdd(vec3 base, vec3 blend) { return min(base + blend, vec3(1.0)); }
        vec3 blendScreen(vec3 base, vec3 blend) { return 1.0 - (1.0 - base) * (1.0 - blend); }
        vec3 blendMultiply(vec3 base, vec3 blend) { return base * blend; }

        void main() {
            vec3 layer1Color = texture2D(u_layer1_texture, vUv).rgb;
            vec3 layer2Color = texture2D(u_image_texture, vUv).rgb;
            vec3 finalColor = layer1Color;
            if (u_layer2_blend_mode == 1) { finalColor = mix(layer1Color, blendAdd(layer1Color, layer2Color), u_layer2_opacity); }
            else if (u_layer2_blend_mode == 2) { finalColor = mix(layer1Color, blendScreen(layer1Color, layer2Color), u_layer2_opacity); }
            else if (u_layer2_blend_mode == 3) { finalColor = mix(layer1Color, blendMultiply(layer1Color, layer2Color), u_layer2_opacity); }
            else { finalColor = mix(layer1Color, layer2Color, u_layer2_opacity); }
            gl_FragColor = vec4(finalColor, 1.0);
        }
    </script>

    <script>
