        // --- AI MANAGER ---
        const AIManager = {
            apiKey: sessionStorage.getItem('geminiApiKey') || '',
            async callApi(prompt, model, jsonSchema = null, isImagen = false) {
                if (!this.apiKey) {
                    showMessage('API Key Missing', 'Please set your Gemini API key in the AI tab.');
                    openModal(DOM.apiKeyModal);
                    return null;
                }
                const url = isImagen ? IMAGEN_API_URL.replace('YOUR_PROJECT_ID', 'your-gcp-project-id-here') + this.apiKey : GEMINI_API_URL + this.apiKey;
                const payload = isImagen ? { instances: [{ prompt: prompt }], parameters: { "sampleCount": 1 } } : { contents: [{ role: "user", parts: [{ text: prompt }] }] };

                if (jsonSchema && !isImagen) {
                    payload.generation_config = { response_mime_type: "application/json" };
                    payload.tool_config = { function_calling_config: { mode: "ANY", allowed_function_names: ["extract_json"] } };
                    payload.tools = [{ function_declarations: [{ name: "extract_json", description: "Extracts JSON based on a schema", parameters: jsonSchema }] }];
                }

                try {
                    const response = await fetch(url, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
                    if (!response.ok) { const errorBody = await response.json(); throw new Error(`API Error: ${errorBody.error?.message || response.statusText}`); }
                    const result = await response.json();

                    if (isImagen) return result;
                    if (!result.candidates?.[0]?.content?.parts?.[0]) throw new Error("No content returned from AI.");

                    const part = result.candidates[0].content.parts[0];
                    if (part.functionCall) {
                        return part.functionCall.args;
                    }
                    return jsonSchema ? JSON.parse(part.text) : part.text;

                } catch (error) {
                    console.error("AI API call failed:", error);
                    showMessage('AI Error', `Failed to get a response. Check console. Error: ${error.message}`);
                    return null;
                }
            },
        };

        // --- VISUALS ENGINE (3D + 2D Shader) ---
        let scene, camera, renderer, controls, clock;
        let generativeMaterial, compositeMaterial, backgroundScene, backgroundCamera, planeMesh;
        let generativeRenderTarget;

        function initVisuals() {
            // 3D Scene
            scene = new THREE.Scene();
            clock = new THREE.Clock();
            camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);
            camera.position.z = 5;
            renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
            renderer.autoClear = false;
            DOM.container.appendChild(renderer.domElement);
            controls = new THREE.OrbitControls(camera, renderer.domElement);
            const geometry = new THREE.BoxGeometry();
            const material = new THREE.MeshNormalMaterial();
            scene.add(new THREE.Mesh(geometry, material));

            // 2D Background Scene
            backgroundScene = new THREE.Scene();
            backgroundCamera = new THREE.OrthographicCamera(-1, 1, 1, -1, 0, 1);
            const targetOptions = { minFilter: THREE.LinearFilter, magFilter: THREE.LinearFilter, format: THREE.RGBAFormat };
            generativeRenderTarget = new THREE.WebGLRenderTarget(window.innerWidth, window.innerHeight, targetOptions);
            const placeholderTexture = new THREE.DataTexture(new Uint8Array([0, 0, 0, 255]), 1, 1, THREE.RGBAFormat);
            placeholderTexture.needsUpdate = true;

            generativeMaterial = new THREE.ShaderMaterial({
                uniforms: {
                    u_time: { value: 0.0 }, u_resolution: { value: new THREE.Vector2() }, u_pattern: { value: 0 },
                    u_complexity: { value: 0.6 }, u_intensity: { value: 1.0 }, u_feedback_texture: { value: generativeRenderTarget.texture }
                },
                vertexShader: $('#vertexShader').textContent, fragmentShader: $('#generativeFragmentShader').textContent
            });

            compositeMaterial = new THREE.ShaderMaterial({
                uniforms: {
                    u_layer1_texture: { value: generativeRenderTarget.texture }, u_image_texture: { value: placeholderTexture },
                    u_layer2_opacity: { value: 0.0 }, u_layer2_blend_mode: { value: 0 }
                },
                vertexShader: $('#vertexShader').textContent, fragmentShader: $('#compositeFragmentShader').textContent
            });

            planeMesh = new THREE.Mesh(new THREE.PlaneGeometry(2, 2), compositeMaterial);
            backgroundScene.add(planeMesh);
            DOM.visualPatternSelect.innerHTML = VISUAL_PATTERNS.map((name, i) => `<option value="${i}">${name}</option>`).join('');

            window.addEventListener('resize', onWindowResize, false);
            onWindowResize();
        }
        function onWindowResize() {
            const controlsWidth = document.body.clientWidth > 768 ? parseInt(getComputedStyle(document.documentElement).getPropertyValue('--controls-width')) : 0;
            const viewWidth = window.innerWidth - controlsWidth;
            const viewHeight = window.innerHeight;
            camera.aspect = viewWidth / viewHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(viewWidth, viewHeight);
            generativeRenderTarget.setSize(viewWidth, viewHeight);
            generativeMaterial.uniforms.u_resolution.value.set(viewWidth, viewHeight);
        }

        // --- TONE.JS AUDIO ENGINE ---
        let masterFilter, masterDelay, masterReverb, audioAnalyser;
        let transportLoop;
        async function setupAudio() {
            await Tone.start();
            audioAnalyser = new Tone.Analyser('fft', 32);
            masterReverb = new Tone.Reverb(2).toDestination();
            masterDelay = new Tone.FeedbackDelay(0, 0).connect(masterReverb);
            masterFilter = new Tone.Filter(20000, "lowpass").connect(audioAnalyser).connect(masterDelay);

