            createNewPattern();
            buildArrangerUI();
            setupDestinations();
            buildModMatrixUI();
            setupMIDI();
        }

        function createNewPattern() {
            const newId = Date.now().toString();
            const newPattern = {
                id: newId, name: `Ptn ${state.patterns.length + 1}`,
                tracks: [
                    { name: 'VIS', type: 'control', data: []},
                    { name: 'Kick', type: 'drum', synthType: 'MembraneSynth', synth: new Tone.MembraneSynth().connect(masterFilter), data: [] },
                    { name: 'Snare', type: 'drum', synthType: 'NoiseSynth', synth: new Tone.NoiseSynth().connect(masterFilter), data: [] },
                    { name: 'Hat', type: 'drum', synthType: 'MetalSynth', synth: new Tone.MetalSynth({frequency: 200, envelope: {attack: 0.001, decay: 0.1, release: 0.01}, harmonicity: 5.1, modulationIndex: 32, resonance: 4000, octaves: 1.5}).connect(masterFilter), data: [] },
                    { name: 'Bass', type: 'melodic', synthType: 'MonoSynth', synth: new Tone.MonoSynth({oscillator: {type: 'sawtooth'}, envelope: {attack: 0.01, decay: 0.2, sustain: 0.2, release: 0.1}, filterEnvelope: {attack: 0.01, decay: 0.1, sustain: 0.1, release: 0.1, baseFrequency: 100, octaves: 4}}).connect(masterFilter), data: [] },
                    { name: 'Poly', type: 'polyphonic', synthType: 'PolySynth', synth: new Tone.PolySynth(Tone.Synth).connect(masterFilter), data: [] },
                    { name: 'Granular', type: 'sampler', synthType: 'GrainPlayer', synth: new Tone.GrainPlayer({ url: "", loop: true, grainSize: 0.2, overlap: 0.1 }).connect(masterFilter), data: [] },
                ]
            };
            newPattern.tracks.forEach(track => {
                track.data = Array.from({ length: state.numSteps }, () => (track.type === 'control' ? { visualClipIndex: null } : { active: 0, note: "C3", pLocks: {} }));
            });
            state.patterns.push(newPattern);
            setActivePattern(newId);
        }

        function setActivePattern(patternId) {
            if (transportLoop) transportLoop.dispose();
            state.activePatternId = patternId;
            const activePattern = state.patterns.find(p => p.id === patternId);
            if (!activePattern) return;

            transportLoop = new Tone.Sequence((time, step) => {
                activePattern.tracks.forEach(track => {
                    const stepData = track.data[step];
                    // Apply P-Locks before triggering
                    if (track.synth && stepData.pLocks) {
                        for (const param in stepData.pLocks) { setSynthParam(track.synth, param, stepData.pLocks[param]); }
                    }
                    // Trigger sound
                    if (stepData.active && track.synth) {
                        if (track.synthType === 'NoiseSynth') track.synth.triggerAttackRelease("8n", time);
                        else if (track.type === 'drum') track.synth.triggerAttackRelease("C1", "8n", time);
                        else if (track.type === 'melodic' || track.type === 'polyphonic') track.synth.triggerAttackRelease(stepData.note, "8n", time);
                        else if (track.type === 'sampler' && track.synth.loaded) track.synth.start(time);

                        if (track.name === 'Kick') state.modulators.kick.value = 1;
                        if (track.name === 'Snare') state.modulators.snare.value = 1;
                    }
                    // Trigger visuals
                    const visTrack = activePattern.tracks.find(t=>t.name==='VIS');
                    if(visTrack && visTrack.data[step].visualClipIndex !== null){
                         applyVisualClip(state.visualClips[visTrack.data[step].visualClipIndex]);
                    }
                });
                Tone.Draw.schedule(() => highlightStep(step), time);
            }, Array.from({ length: state.numSteps }, (_, i) => i), "16n").start(0);

            buildSequencerUI();
            buildSynthControlsUI();
            buildArrangerUI();
            updateAiSynthTargetDropdown();
        }

        // --- UI & WORKFLOW ---
        function buildSequencerUI() {
            const activePattern = state.patterns.find(p => p.id === state.activePatternId);
            if (!activePattern) { DOM.sequencerContainer.innerHTML = ''; return; }
            DOM.sequencerContainer.innerHTML = '';
            DOM.sequencerContainer.style.setProperty('--num-steps', state.numSteps);
            activePattern.tracks.forEach((track, trackIndex) => {
                const trackEl = document.createElement('div');
                trackEl.className = 'track';
                trackEl.dataset.trackIndex = trackIndex;
                let stepsHTML = '';
                for(let i=0; i < state.numSteps; i++) {
                    const stepData = track.data[i];
                    let classes = 'step';
                    if (stepData.active || (track.name === 'VIS' && stepData.visualClipIndex !== null)) classes += ' on';
                    if (track.name === 'VIS' && stepData.visualClipIndex !== null) classes += ' visual';
                    if (stepData.pLocks && Object.keys(stepData.pLocks).length > 0) classes += ' has-plock';
                    const noteLabel = (track.type === 'melodic' || track.type === 'polyphonic') && stepData.note ? stepData.note.replace('#', '♯') : '';
                    stepsHTML += `<div class="${classes}" data-step-index="${i}"><div class="step-content">${noteLabel}</div></div>`;
                }
                trackEl.innerHTML = `<div class="track-header"><span class="track-label" title="${track.name}">${track.name}</span><button class="clear-track-btn" title="Clear Pattern">[ C ]</button></div><div class="steps">${stepsHTML}</div>`;
                DOM.sequencerContainer.appendChild(trackEl);
            });
        }

        function highlightStep(step) {
            $$('.step.active').forEach(el => el.classList.remove(CLASSES.ACTIVE));
            $$(`.step[data-step-index='${step}']`).forEach(el => el.classList.add(CLASSES.ACTIVE));
        }

        function buildSynthControlsUI() {
             const activePattern = state.patterns.find(p => p.id === state.activePatternId);
             if (!activePattern) return;
             DOM.synthControlsContainer.innerHTML = '';
             activePattern.tracks.filter(t => t.synth).forEach(track => {
                 const details = document.createElement('details');
                 details.open = true;
                 details.innerHTML = `<summary>${track.name}</summary>`;
                 const controls = getAdvancedControlsForSynth(track);
                 for (const param in controls) {
                     const control = controls[param];
                     const id = `${track.name}-${param.replace(/\./g, '-')}`;
                     const label = document.createElement('label'); label.htmlFor = id; label.textContent = param;
                     const input = document.createElement('input');
                     input.type = 'range'; input.id = id; input.min = control.min; input.max = control.max; input.step = control.step; input.value = control.value;
                     input.dataset.paramPath = param; input.dataset.trackName = track.name;
                     input.addEventListener('input', (e) => setSynthParam(track.synth, param, parseFloat(e.target.value)));
                     details.append(label, input);
                 }
                 DOM.synthControlsContainer.appendChild(details);
             });
        }

        function buildArrangerUI() {
            DOM.patternClipsContainer.innerHTML = '';
            state.patterns.forEach(pattern => {
                const clipEl = document.createElement('div');
                clipEl.className = 'pattern-clip';
                clipEl.classList.toggle('active-pattern', pattern.id === state.activePatternId);
                clipEl.textContent = pattern.name; clipEl.dataset.patternId = pattern.id; clipEl.draggable = true;
                clipEl.addEventListener('dragstart', e => e.dataTransfer.setData('pattern/id', pattern.id));
                clipEl.addEventListener('click', () => setActivePattern(pattern.id));
                DOM.patternClipsContainer.appendChild(clipEl);
            });
            DOM.masterTrackContainer.innerHTML = '';
            state.arrangement.forEach((patternId, index) => {
                const slotEl = document.createElement('div');
                slotEl.className = 'master-track-slot'; slotEl.dataset.index = index;
                if (patternId !== null) {
                    const pattern = state.patterns.find(p => p.id === patternId);
                    slotEl.textContent = pattern ? pattern.name : '??';
                    slotEl.style.backgroundColor = 'var(--step-on)';
                }
                DOM.masterTrackContainer.appendChild(slotEl);
            });
        }

        function buildModMatrixUI() {
            DOM.modMatrixContainer.innerHTML = '';
            const sources = Object.keys(state.modulators); const targets = Object.keys(state.destinations);
            state.modMatrix.forEach((mod, index) => {
                const row = document.createElement('div'); row.style.cssText = 'display:grid; grid-template-columns:1fr 1fr 2fr; gap:10px; margin-bottom:5px;';
                const sourceSelect = document.createElement('select'); sourceSelect.innerHTML = sources.map(s => `<option value="${s}" ${s === mod.source ? 'selected' : ''}>${s}</option>`).join('');
                sourceSelect.addEventListener('change', (e) => { state.modMatrix[index].source = e.target.value; });
                const targetSelect = document.createElement('select'); targetSelect.innerHTML = targets.map(t => `<option value="${t}" ${t === mod.target ? 'selected' : ''}>${t}</option>`).join('');
                targetSelect.addEventListener('change', (e) => { state.modMatrix[index].target = e.target.value; });
                const amountSlider = document.createElement('input'); amountSlider.type = 'range'; amountSlider.min = -1; amountSlider.max = 1; amountSlider.step = 0.01; amountSlider.value = mod.amount;
                amountSlider.addEventListener('input', (e) => { state.modMatrix[index].amount = parseFloat(e.target.value); });
                row.append(sourceSelect, targetSelect, amountSlider);
                DOM.modMatrixContainer.appendChild(row);
            });
        }

        function openModal(modal) { DOM.modalOverlay.classList.add(CLASSES.OPEN); modal.classList.add(CLASSES.OPEN); }
        function closeModal() { $$('.modal.open').forEach(m => m.classList.remove(CLASSES.OPEN)); DOM.modalOverlay.classList.remove(CLASSES.OPEN); }
        function showMessage(title, text) { $('#message-title').textContent = title; $('#message-text').textContent = text; openModal($('#message-modal')); }

        function updateAiSynthTargetDropdown() {
            const activePattern = state.patterns.find(p => p.id === state.activePatternId);
            if (!activePattern) { DOM.aiSynthTarget.innerHTML = ''; return; }
            DOM.aiSynthTarget.innerHTML = '';
            activePattern.tracks.filter(t => t.synth).forEach((track) => {
                const option = document.createElement('option');
                option.value = track.name; option.textContent = track.name;
                DOM.aiSynthTarget.appendChild(option);
            });
        }

        function setupDestinations() {
            const activePattern = state.patterns.find(p => p.id === state.activePatternId);
            if (!activePattern) return;
            const bassSynth = activePattern.tracks.find(t=>t.name==='Bass').synth;
            state.destinations = {
                complexity: { obj: generativeMaterial.uniforms.u_complexity, prop: 'value', min: 0, max: 1 },
                intensity: { obj: generativeMaterial.uniforms.u_intensity, prop: 'value', min: 0, max: 2 },
                masterFilter: { obj: masterFilter.frequency, prop: 'value', min: 20, max: 20000 },
                masterDelay: { obj: masterDelay.feedback, prop: 'value', min: 0, max: 0.9 },
                masterReverb: { obj: masterReverb, prop: 'wet', min: 0, max: 1 },
                bassFltFreq: { obj: bassSynth.filter.frequency, prop: 'value', min: 20, max: 10000 },
                bassFltQ: { obj: bassSynth.filter.Q, prop: 'value', min: 0.1, max: 10 },
            };
        }

        function getAdvancedControlsForSynth(track) {
            const synth = track.synth;
            if (!synth) return {};
