            width: 100px;
            font-weight: 600;
            font-size: 12px;
            cursor: pointer;
            padding: 4px 8px;
            background: rgba(255,255,255,0.05);
            border-radius: 4px;
            transition: all 0.2s;
        }

        .track-label:hover { background: rgba(0,212,255,0.1); color: var(--accent-primary); }

        .steps {
            display: grid;
            grid-template-columns: repeat(var(--steps, 16), 1fr);
            gap: 4px;
            flex: 1;
        }

        .step {
            aspect-ratio: 1;
            background: rgba(255,255,255,0.1);
            border: 1px solid transparent;
            border-radius: 4px;
            cursor: pointer;
            transition: all 0.15s;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 9px;
            font-weight: 600;
        }

        .step:hover { background: rgba(255,255,255,0.2); transform: scale(1.05); }
        .step.on { background: var(--accent-primary); color: white; }
        .step.visual { background: #ff00ff; color: white; }
        .step.active { border-color: var(--accent-secondary); transform: scale(1.1); }

        .piano-keys {
            width: 60px;
            background: var(--panel-bg);
            border-right: 1px solid var(--border-primary);
            overflow-y: auto;
        }

        .key {
            height: 12px;
            border-bottom: 1px solid var(--border-secondary);
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 9px;
            cursor: pointer;
        }

        .key.white { background: #f0f0f0; color: #333; }
        .key.black { background: #333; color: white; margin: -6px 0 -6px 20px; position: relative; }
        .key:hover { background: var(--accent-primary); color: white; }

        .piano-grid-container { flex: 1; overflow: auto; }
        .piano-grid { 
            display: grid; 
            grid-template-columns: repeat(var(--steps, 16), 32px); 
            grid-auto-rows: 12px;
        }

        .piano-cell {
            background: rgba(255,255,255,0.02);
            border: 1px solid var(--border-secondary);
            cursor: pointer;
        }

        .piano-cell:hover { background: rgba(255,255,255,0.08); }
        .piano-cell.note { background: var(--accent-primary); }

        .kaoss-pad-container { padding: 16px; border-top: 1px solid var(--border-primary); }
        .kaoss-pad {
            width: 120px;
            height: 120px;
            margin: 0 auto;
            background: var(--panel-secondary);
            border: 2px solid var(--border-primary);
            border-radius: 8px;
            position: relative;
            cursor: crosshair;
        }

        .kaoss-indicator {
            position: absolute;
            width: 12px;
            height: 12px;
            background: var(--accent-primary);
            border-radius: 50%;
            transform: translate(-50%, -50%);
            opacity: 0;
            transition: opacity 0.2s;
        }

        .modal-overlay {
            position: fixed;
            inset: 0;
            background: rgba(0,0,0,0.8);
            backdrop-filter: blur(5px);
            z-index: 1000;
            display: flex;
            align-items: center;
            justify-content: center;
            opacity: 0;
            visibility: hidden;
            transition: all 0.3s;
        }

        .modal-overlay.open { opacity: 1; visibility: visible; }

        .modal {
            background: var(--panel-bg);
            border: 1px solid var(--border-primary);
            border-radius: 12px;
            padding: 24px;
            max-width: 400px;
            width: 90%;
            box-shadow: var(--shadow);
        }

        .modal h3 { color: var(--accent-primary); margin-bottom: 16px; }

        .hidden { display: none; }
        .loader { 
            width: 20px; 
            height: 20px; 
            border: 2px solid var(--border-primary); 
            border-top: 2px solid var(--accent-primary); 
            border-radius: 50%; 
            animation: spin 1s linear infinite; 
            margin: 8px auto;
        }

        @keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }

        @media (max-width: 768px) {
            #app { grid-template-columns: 1fr; }
            #controls { 
                position: fixed; 
                top: 0; 
                right: 0; 
                bottom: 0; 
                width: 100%; 
                transform: translateX(100%); 
                transition: transform 0.3s;
                z-index: 100;
            }
            #controls.open { transform: translateX(0); }
            #sequencer, #piano-roll { right: 0; }
        }
    </style>
</head>
<body>
