    <!-- Modals -->
    <div class="modal-overlay" id="modal-overlay">
        <div class="modal">
            <h3 id="modal-title">Welcome to Dopamine Lab v26</h3>
            <p id="modal-text">Click "Start Audio" to begin creating music with the enhanced Genesis Engine.</p>
            <button id="start-audio-btn" class="btn">Start Audio Engine</button>
        </div>
    </div>

    <!-- Mobile Menu Toggle -->
    <button id="mobile-toggle" class="btn" style="position: fixed; bottom: 20px; right: 20px; z-index: 200; display: none; width: auto; border-radius: 50%; padding: 12px;">☰</button>

    <!-- Scripts -->
    <script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>
    <script src="https://cdnjs.cloudflare.com/ajax/libs/tone/14.7.77/Tone.js"></script>

    <script>
class DopamineLab {
    constructor() {
        this.audioReady = false;
        this.isPlaying = false;
        this.currentStep = 0;
        this.numSteps = 16;
        this.patterns = [];
        this.activePatternId = null;
        this.isPianoOpen = false;
        this.activePianoTrack = null;

        // Visual engine
        this.scene = null;
        this.camera = null;
        this.renderer = null;
        this.clock = new THREE.Clock();
        this.materials = {};

        // Audio engine
        this.masterBus = null;
        this.transportLoop = null;

        this.init();
    }

    init() {
        this.setupDOM();
        this.setupVisuals();
        this.bindEvents();
        this.showWelcomeModal();
        this.animate();
    }

    setupDOM() {
        // Cache frequently used elements
        this.dom = {
            canvas: document.getElementById('canvas'),
            playBtn: document.getElementById('play-btn'),
            playTransport: document.getElementById('play-transport'),
            bpmSlider: document.getElementById('bpm-slider'),
            bpmDisplay: document.getElementById('bpm-display'),
            bpmLive: document.getElementById('bpm-live'),
            stepsSelect: document.getElementById('steps-select'),
            tracksContainer: document.getElementById('tracks-container'),
            pianoRoll: document.getElementById('piano-roll'),
            pianoKeys: document.getElementById('piano-keys'),
            pianoGrid: document.getElementById('piano-grid'),
            sequencer: document.getElementById('sequencer'),
            controls: document.getElementById('controls'),
            mobileToggle: document.getElementById('mobile-toggle'),
            modalOverlay: document.getElementById('modal-overlay'),
            startAudioBtn: document.getElementById('start-audio-btn'),
            // Visual controls
            visualPattern: document.getElementById('visual-pattern'),
            complexity: document.getElementById('complexity'),
            intensity: document.getElementById('intensity'),
            randomizeVisualBtn: document.getElementById('randomize-visual-btn'),
            // Other controls
            saveBtn: document.getElementById('save-btn'),
            loadBtn: document.getElementById('load-btn'),
            fileInput: document.getElementById('file-input'),
            randomBtn: document.getElementById('random-btn'),
            newPatternBtn: document.getElementById('new-pattern-btn'),
            addSynthBtn: document.getElementById('add-synth-btn'),
            apiKey: document.getElementById('api-key'),
            aiPrompt: document.getElementById('ai-prompt'),
            generateBtn: document.getElementById('generate-btn'),
            aiLoader: document.getElementById('ai-loader'),
        };

        // Show mobile toggle on small screens
        if (window.innerWidth <= 768) {
            this.dom.mobileToggle.style.display = 'block';
        }
    }

    setupVisuals() {
        const canvas = this.dom.canvas;
        const rect = canvas.parentElement.getBoundingClientRect();

        this.scene = new THREE.Scene();
        this.camera = new THREE.PerspectiveCamera(75, rect.width / rect.height, 0.1, 1000);
        this.camera.position.z = 5;

        this.renderer = new THREE.WebGLRenderer({ canvas, antialias: true, alpha: true });
        this.renderer.setSize(rect.width, rect.height);
        this.renderer.setClearColor(0x000000, 0);

        // Create visual materials
        this.createVisualMaterials();

        // Create background plane
        const geometry = new THREE.PlaneGeometry(20, 20);
        const mesh = new THREE.Mesh(geometry, this.materials.background);
        this.scene.add(mesh);

        // Add some 3D objects
        this.add3DObjects();

        window.addEventListener('resize', () => this.onWindowResize());
    }

    createVisualMaterials() {
        const vertexShader = `
            varying vec2 vUv;
            void main() {
                vUv = uv;
                gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
            }
        `;

        const fragmentShader = `
            uniform float u_time;
            uniform vec2 u_resolution;
            uniform float u_pattern;
            uniform float u_complexity;
            uniform float u_intensity;
            varying vec2 vUv;

            float random(vec2 st) {
                return fract(sin(dot(st.xy, vec2(12.9898, 78.233))) * 43758.5453123);
            }

            float noise(vec2 st) {
                vec2 i = floor(st);
                vec2 f = fract(st);
                vec2 u = f * f * (3.0 - 2.0 * f);
                return mix(
                    mix(random(i + vec2(0.0,0.0)), random(i + vec2(1.0,0.0)), u.x),
                    mix(random(i + vec2(0.0,1.0)), random(i + vec2(1.0,1.0)), u.x), 
                    u.y
                );
            }

            vec3 hsv2rgb(vec3 c) {
                vec4 K = vec4(1.0, 2.0 / 3.0, 1.0 / 3.0, 3.0);
                vec3 p = abs(fract(c.xxx + K.xyz) * 6.0 - K.www);
                return c.z * mix(K.xxx, clamp(p - K.xxx, 0.0, 1.0), c.y);
            }

            void main() {
                vec2 st = vUv;
                vec3 color = vec3(0.0);

                float time = u_time * 0.5;

                if (u_pattern < 0.5) {
                    // Fluid pattern
                    float n = 0.0;
                    float amplitude = 1.0;
                    vec2 pos = st * (2.0 + u_complexity * 4.0);

                    for (int i = 0; i < 6; i++) {
                        n += amplitude * noise(pos + time);
                        pos *= 2.0;
                        amplitude *= 0.5;
                    }

                    float hue = fract(time * 0.1 + n * 0.5);
                    color = hsv2rgb(vec3(hue, 0.8, n * u_intensity));

                } else if (u_pattern < 1.5) {
                    // Geometric pattern
                    vec2 pos = st - 0.5;
                    float angle = atan(pos.y, pos.x);
                    float radius = length(pos);

                    float pattern = sin(angle * (6.0 + u_complexity * 12.0) + time) * 
                                   cos(radius * (10.0 + u_complexity * 20.0) - time);

                    float hue = fract(time * 0.2 + pattern * 0.3);
                    color = hsv2rgb(vec3(hue, 0.9, abs(pattern) * u_intensity));

                } else if (u_pattern < 2.5) {
                    // Organic pattern
                    vec2 pos = st * (1.0 + u_complexity * 2.0);
                    float n1 = noise(pos + time);
                    float n2 = noise(pos * 2.0 - time * 0.5);
                    float n3 = noise(pos * 4.0 + time * 0.3);

                    float combined = n1 * 0.5 + n2 * 0.3 + n3 * 0.2;
                    float hue = fract(time * 0.15 + combined);
                    color = hsv2rgb(vec3(hue, 0.7, combined * u_intensity));

                } else {
                    // Kaleidoscope pattern
                    vec2 pos = st - 0.5;
                    float angle = atan(pos.y, pos.x);
                    float radius = length(pos);

                    float sides = 6.0 + u_complexity * 6.0;
                    angle = mod(angle, 6.28318 / sides);
                    angle = abs(angle - 3.14159 / sides);

                    vec2 kaleidoPos = radius * vec2(cos(angle), sin(angle));
                    float pattern = noise(kaleidoPos * 8.0 + time);

                    float hue = fract(time * 0.1 + radius);
                    color = hsv2rgb(vec3(hue, 0.9, pattern * u_intensity));
                }

                gl_FragColor = vec4(color, 1.0);
            }
        `;

        this.materials.background = new THREE.ShaderMaterial({
            uniforms: {
                u_time: { value: 0.0 },
                u_resolution: { value: new THREE.Vector2() },
                u_pattern: { value: 0.0 },
                u_complexity: { value: 0.5 },
                u_intensity: { value: 1.0 }
            },
            vertexShader,
            fragmentShader
        });
    }

    add3DObjects() {
        // Add some rotating geometric objects
        const geometries = [
            new THREE.BoxGeometry(1, 1, 1),
            new THREE.SphereGeometry(0.5, 16, 16),
            new THREE.ConeGeometry(0.5, 1, 8),
            new THREE.TorusGeometry(0.5, 0.2, 8, 16)
        ];

        for (let i = 0; i < 4; i++) {
            const material = new THREE.MeshNormalMaterial({ wireframe: Math.random() > 0.5 });
            const mesh = new THREE.Mesh(geometries[i], material);

            mesh.position.set(
                (Math.random() - 0.5) * 8,
                (Math.random() - 0.5) * 8,
                (Math.random() - 0.5) * 4
            );

            mesh.userData = {
                rotationSpeed: new THREE.Vector3(
                    (Math.random() - 0.5) * 0.02,
                    (Math.random() - 0.5) * 0.02,
                    (Math.random() - 0.5) * 0.02
                )
            };

            this.scene.add(mesh);
        }
    }

    onWindowResize() {
        const rect = this.dom.canvas.parentElement.getBoundingClientRect();
        this.camera.aspect = rect.width / rect.height;
        this.camera.updateProjectionMatrix();
        this.renderer.setSize(rect.width, rect.height);
        this.materials.background.uniforms.u_resolution.value.set(rect.width, rect.height);
    }

    async setupAudio() {
        try {
            await Tone.start();

            // Create master bus with effects
            this.masterBus = new Tone.Gain(0.8).toDestination();
            const reverb = new Tone.Reverb(2).connect(this.masterBus);
            const delay = new Tone.FeedbackDelay(0.25, 0.3).connect(reverb);
            const filter = new Tone.Filter(20000, "lowpass").connect(delay);

            // Set initial BPM
            Tone.Transport.bpm.value = 120;

            this.audioReady = true;
            this.dom.playBtn.disabled = false;
            this.dom.playBtn.textContent = 'Play';
            this.dom.playTransport.disabled = false;
            this.dom.playTransport.textContent = 'Play';

            // Create initial pattern
            this.createNewPattern();
            this.buildSequencerUI();

        } catch (error) {
            console.error('Audio setup failed:', error);
            this.showModal('Audio Error', 'Failed to initialize audio engine. Please check your browser permissions.');
        }
    }

    createNewPattern() {
        const patternId = Date.now().toString();
        const pattern = {
            id: patternId,
            name: `Pattern ${this.patterns.length + 1}`,
            tracks: [
                {
                    name: 'VIS',
                    type: 'visual',
                    data: Array(this.numSteps).fill(null).map(() => ({ active: false, visualClip: null }))
                },
                {
                    name: 'Kick',
                    type: 'drum',
                    synth: new Tone.MembraneSynth().connect(this.masterBus),
                    data: Array(this.numSteps).fill(null).map(() => ({ active: false, note: 'C1' }))
                },
                {
                    name: 'Snare',
                    type: 'drum',
                    synth: new Tone.NoiseSynth().connect(this.masterBus),
                    data: Array(this.numSteps).fill(null).map(() => ({ active: false, note: 'C1' }))
                },
                {
                    name: 'Hi-Hat',
                    type: 'drum',
                    synth: new Tone.MetalSynth({ frequency: 200, envelope: { attack: 0.001, decay: 0.1, release: 0.01 } }).connect(this.masterBus),
                    data: Array(this.numSteps).fill(null).map(() => ({ active: false, note: 'C1' }))
                },
                {
                    name: 'Bass',
                    type: 'melodic',
                    synth: new Tone.MonoSynth({ oscillator: { type: 'sawtooth' }, envelope: { attack: 0.01, decay: 0.2, sustain: 0.2, release: 0.1 } }).connect(this.masterBus),
                    data: Array(this.numSteps).fill(null).map(() => ({ active: false, note: 'C2' }))
                },
                {
                    name: 'Lead',
                    type: 'melodic',
                    synth: new Tone.PolySynth(Tone.Synth).connect(this.masterBus),
                    data: Array(this.numSteps).fill(null).map(() => ({ active: false, note: 'C4' }))
                }
            ]
        };

        this.patterns.push(pattern);
        this.setActivePattern(patternId);
    }

    setActivePattern(patternId) {
        this.activePatternId = patternId;

        // Stop existing transport
        if (this.transportLoop) {
            this.transportLoop.dispose();
        }

        const pattern = this.getActivePattern();
        if (!pattern) return;

        // Create new transport loop
        this.transportLoop = new Tone.Sequence((time, step) => {
            this.triggerStep(pattern, step, time);
            Tone.Draw.schedule(() => {
                this.highlightStep(step);
            }, time);
        }, Array.from({ length: this.numSteps }, (_, i) => i), "16n").start(0);

        this.buildSequencerUI();
        document.getElementById('pattern-name').textContent = pattern.name;
    }

    triggerStep(pattern, step, time) {
        pattern.tracks.forEach(track => {
            const stepData = track.data[step];

            if (stepData.active && track.synth) {
                if (track.type === 'drum') {
                    if (track.name === 'Snare') {
                        track.synth.triggerAttackRelease("8n", time);
                    } else {
                        track.synth.triggerAttackRelease(stepData.note, "8n", time);
                    }
                } else if (track.type === 'melodic') {
                    track.synth.triggerAttackRelease(stepData.note, "8n", time);
                }
            }

            // Trigger visual effects
            if (track.type === 'visual' && stepData.active && stepData.visualClip) {
                this.applyVisualClip(stepData.visualClip);
            }
        });
    }

    highlightStep(step) {
        document.querySelectorAll('.step.active').forEach(el => el.classList.remove('active'));
        document.querySelectorAll(`[data-step="${step}"]`).forEach(el => el.classList.add('active'));
        this.currentStep = step;
    }

    buildSequencerUI() {
        const pattern = this.getActivePattern();
        if (!pattern) return;

        this.dom.tracksContainer.innerHTML = '';
        this.dom.tracksContainer.style.setProperty('--steps', this.numSteps);

        pattern.tracks.forEach((track, trackIndex) => {
            const trackEl = document.createElement('div');
            trackEl.className = 'track';
            trackEl.innerHTML = `
                <div class="track-label" data-track="${trackIndex}">${track.name}</div>
                <div class="steps">
                    ${track.data.map((step, stepIndex) => `
                        <div class="step ${step.active ? 'on' : ''} ${track.type === 'visual' && step.active ? 'visual' : ''}" 
                             data-track="${trackIndex}" 
                             data-step="${stepIndex}">
                        </div>
                    `).join('')}
                </div>
            `;
            this.dom.tracksContainer.appendChild(trackEl);
        });
    }

    buildPianoRoll() {
        if (!this.activePianoTrack) return;

        const pattern = this.getActivePattern();
        const track = pattern.tracks[this.activePianoTrack];

        // Build piano keys
        const notes = ['C', 'C#', 'D', 'D#', 'E', 'F', 'F#', 'G', 'G#', 'A', 'A#', 'B'];
        const octaves = [6, 5, 4, 3, 2, 1];

        this.dom.pianoKeys.innerHTML = '';
        const allNotes = [];

        octaves.forEach(octave => {
            notes.slice().reverse().forEach(note => {
                const noteName = note + octave;
                allNotes.push(noteName);

                const keyEl = document.createElement('div');
                keyEl.className = `key ${note.includes('#') ? 'black' : 'white'}`;
                keyEl.textContent = noteName;
                keyEl.dataset.note = noteName;
                this.dom.pianoKeys.appendChild(keyEl);
            });
        });

        // Build piano grid
        this.dom.pianoGrid.innerHTML = '';
        this.dom.pianoGrid.style.setProperty('--steps', this.numSteps);

        allNotes.forEach(note => {
            for (let step = 0; step < this.numSteps; step++) {
                const cellEl = document.createElement('div');
                cellEl.className = 'piano-cell';
                cellEl.dataset.note = note;
                cellEl.dataset.step = step;

                // Check if this note is active on this step
                const stepData = track.data[step];
                if (stepData.active && stepData.note === note) {
                    cellEl.classList.add('note');
                }

                this.dom.pianoGrid.appendChild(cellEl);
            }
        });
    }

    bindEvents() {
        // Tab switching
        document.querySelectorAll('.tab-btn').forEach(btn => {
            btn.addEventListener('click', () => this.switchTab(btn.dataset.tab));
        });

        // Audio controls
        this.dom.startAudioBtn.addEventListener('click', async () => {
            await this.setupAudio();
            this.hideModal();
        });

        this.dom.playBtn.addEventListener('click', () => this.togglePlayback());
        this.dom.playTransport.addEventListener('click', () => this.togglePlayback());

        this.dom.bpmSlider.addEventListener('input', (e) => {
            const bpm = parseInt(e.target.value);
            Tone.Transport.bpm.value = bpm;
            this.dom.bpmDisplay.textContent = bpm;
            this.dom.bpmLive.textContent = bpm;
        });

        this.dom.stepsSelect.addEventListener('change', (e) => {
            this.numSteps = parseInt(e.target.value);
            this.setActivePattern(this.activePatternId);
        });

        // Sequencer interaction
        this.dom.tracksContainer.addEventListener('click', (e) => {
            if (e.target.classList.contains('step')) {
                this.toggleStep(e.target);
            } else if (e.target.classList.contains('track-label')) {
                this.openPianoRoll(parseInt(e.target.dataset.track));
            }
        });

        // Piano roll interaction
        this.dom.pianoGrid.addEventListener('click', (e) => {
            if (e.target.classList.contains('piano-cell')) {
                this.togglePianoNote(e.target);
            }
        });

        this.dom.pianoKeys.addEventListener('click', (e) => {
            if (e.target.classList.contains('key')) {
                this.playNote(e.target.dataset.note);
            }
        });

        // Visual controls
        this.dom.visualPattern.addEventListener('change', (e) => {
            this.materials.background.uniforms.u_pattern.value = parseFloat(e.target.value);
        });

        this.dom.complexity.addEventListener('input', (e) => {
            this.materials.background.uniforms.u_complexity.value = parseFloat(e.target.value);
        });

        this.dom.intensity.addEventListener('input', (e) => {
            this.materials.background.uniforms.u_intensity.value = parseFloat(e.target.value);
        });

        this.dom.randomizeVisualBtn.addEventListener('click', () => this.randomizeVisuals());

        // Other controls
        this.dom.randomBtn.addEventListener('click', () => this.randomizeAll());
        this.dom.newPatternBtn.addEventListener('click', () => this.createNewPattern());
        this.dom.saveBtn.addEventListener('click', () => this.saveProject());
        this.dom.loadBtn.addEventListener('click', () => this.dom.fileInput.click());
        this.dom.fileInput.addEventListener('change', (e) => this.loadProject(e));

        // AI
        this.dom.generateBtn.addEventListener('click', () => this.generateWithAI());

        // Mobile
        this.dom.mobileToggle.addEventListener('click', () => {
            this.dom.controls.classList.toggle('open');
        });

        // Close piano roll when clicking outside
        document.addEventListener('click', (e) => {
            if (this.isPianoOpen && !this.dom.pianoRoll.contains(e.target) && !e.target.classList.contains('track-label')) {
                this.closePianoRoll();
            }
        });

        // Keyboard shortcuts
        document.addEventListener('keydown', (e) => {
            if (e.code === 'Space') {
                e.preventDefault();
                this.togglePlayback();
            }
            if (e.code === 'Escape' && this.isPianoOpen) {
                this.closePianoRoll();
            }
        });
    }

    switchTab(tabId) {
        document.querySelectorAll('.tab-btn').forEach(btn => btn.classList.remove('active'));
        document.querySelectorAll('.tab-content').forEach(content => content.classList.remove('active'));

        document.querySelector(`[data-tab="${tabId}"]`).classList.add('active');
        document.getElementById(tabId).classList.add('active');
    }

    togglePlayback() {
        if (!this.audioReady) return;

        this.isPlaying = !this.isPlaying;

        if (this.isPlaying) {
            Tone.Transport.start();
            this.dom.playBtn.textContent = 'Stop';
            this.dom.playTransport.textContent = 'Stop';
        } else {
            Tone.Transport.stop();
            this.dom.playBtn.textContent = 'Play';
            this.dom.playTransport.textContent = 'Play';
            this.currentStep = 0;
            document.querySelectorAll('.step.active').forEach(el => el.classList.remove('active'));
        }
    }

    toggleStep(stepEl) {
        const trackIndex = parseInt(stepEl.dataset.track);
        const stepIndex = parseInt(stepEl.dataset.step);

        const pattern = this.getActivePattern();
        const track = pattern.tracks[trackIndex];
        const stepData = track.data[stepIndex];

        stepData.active = !stepData.active;
        stepEl.classList.toggle('on', stepData.active);

        if (track.type === 'visual') {
            stepEl.classList.toggle('visual', stepData.active);
            if (stepData.active) {
                stepData.visualClip = this.captureCurrentVisualState();
            }
        }
    }

    openPianoRoll(trackIndex) {
        const pattern = this.getActivePattern();
        const track = pattern.tracks[trackIndex];

        if (track.type !== 'melodic') return;

        this.activePianoTrack = trackIndex;
        this.isPianoOpen = true;
        this.dom.pianoRoll.classList.add('open');
        this.dom.sequencer.classList.add('piano-open');

        this.buildPianoRoll();
    }

    closePianoRoll() {
        this.isPianoOpen = false;
        this.activePianoTrack = null;
        this.dom.pianoRoll.classList.remove('open');
        this.dom.sequencer.classList.remove('piano-open');
    }

    togglePianoNote(cellEl) {
        const note = cellEl.dataset.note;
        const step = parseInt(cellEl.dataset.step);

        const pattern = this.getActivePattern();
        const track = pattern.tracks[this.activePianoTrack];
        const stepData = track.data[step];

        if (cellEl.classList.contains('note')) {
            // Remove note
            stepData.active = false;
            cellEl.classList.remove('note');
        } else {
            // Add note
            stepData.active = true;
            stepData.note = note;
            cellEl.classList.add('note');
        }

        this.buildSequencerUI();
    }

    playNote(note) {
        if (!this.audioReady || this.activePianoTrack === null) return;

        const pattern = this.getActivePattern();
        const track = pattern.tracks[this.activePianoTrack];

        if (track.synth) {
            track.synth.triggerAttackRelease(note, "8n");
        }
    }

    captureCurrentVisualState() {
        return {
            pattern: this.materials.background.uniforms.u_pattern.value,
            complexity: this.materials.background.uniforms.u_complexity.value,
            intensity: this.materials.background.uniforms.u_intensity.value
        };
    }

    applyVisualClip(clip) {
        if (clip.pattern !== undefined) this.materials.background.uniforms.u_pattern.value = clip.pattern;
        if (clip.complexity !== undefined) this.materials.background.uniforms.u_complexity.value = clip.complexity;
        if (clip.intensity !== undefined) this.materials.background.uniforms.u_intensity.value = clip.intensity;

        // Update UI controls
        this.dom.visualPattern.value = clip.pattern || 0;
        this.dom.complexity.value = clip.complexity || 0.5;
        this.dom.intensity.value = clip.intensity || 1;
    }

    randomizeVisuals() {
        this.dom.visualPattern.value = Math.floor(Math.random() * 4);
        this.dom.complexity.value = Math.random();
        this.dom.intensity.value = Math.random() * 2;

        this.materials.background.uniforms.u_pattern.value = parseFloat(this.dom.visualPattern.value);
        this.materials.background.uniforms.u_complexity.value = parseFloat(this.dom.complexity.value);
        this.materials.background.uniforms.u_intensity.value = parseFloat(this.dom.intensity.value);
    }

    randomizeAll() {
        const pattern = this.getActivePattern();
        if (!pattern) return;

        // Randomize patterns
        pattern.tracks.forEach(track => {
            if (track.type !== 'visual') {
                track.data.forEach(step => {
                    step.active = Math.random() > 0.7;
                });
            }
        });

        // Randomize visuals
        this.randomizeVisuals();

        this.buildSequencerUI();
    }

    async generateWithAI() {
        const apiKey = this.dom.apiKey.value;
        const prompt = this.dom.aiPrompt.value;

        if (!apiKey || !prompt) {
            this.showModal('Missing Input', 'Please enter your API key and describe what you want to create.');
            return;
        }

        this.dom.aiLoader.classList.remove('hidden');
        this.dom.generateBtn.disabled = true;

        try {
            const response = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/gemini-pro:generateContent?key=${apiKey}`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    contents: [{
                        parts: [{
                            text: `You are an AI music producer. Based on this request: "${prompt}", generate a simple drum pattern as a JSON array of 16 steps where each step is true (drum hit) or false (silence). Respond with only the JSON array, no other text.`
                        }]
                    }]
                })
            });

            const data = await response.json();
            const text = data.candidates?.[0]?.content?.parts?.[0]?.text;

            if (text) {
                try {
                    const pattern = JSON.parse(text.trim());
                    if (Array.isArray(pattern) && pattern.length === 16) {
                        this.applyAIPattern(pattern);
                        this.showModal('AI Generation Complete', 'Your AI-generated pattern has been applied to the kick track!');
                    }
                } catch (e) {
                    throw new Error('Invalid pattern format');
                }
            }

        } catch (error) {
            console.error('AI generation failed:', error);
            this.showModal('AI Error', 'Failed to generate pattern. Please check your API key and try again.');
        } finally {
            this.dom.aiLoader.classList.add('hidden');
            this.dom.generateBtn.disabled = false;
        }
    }

    applyAIPattern(pattern) {
        const activePattern = this.getActivePattern();
        if (!activePattern) return;

        const kickTrack = activePattern.tracks.find(t => t.name === 'Kick');
        if (kickTrack) {
            pattern.forEach((hit, index) => {
                if (index < kickTrack.data.length) {
                    kickTrack.data[index].active = hit;
                }
            });
            this.buildSequencerUI();
        }
    }

    saveProject() {
        const projectData = {
            patterns: this.patterns,
            numSteps: this.numSteps,
            bpm: Tone.Transport.bpm.value,
            version: '26'
        };

        const dataStr = JSON.stringify(projectData, null, 2);
        const dataBlob = new Blob([dataStr], { type: 'application/json' });

        const link = document.createElement('a');
        link.href = URL.createObjectURL(dataBlob);
        link.download = `dopamine-project-${Date.now()}.json`;
        link.click();
    }

    loadProject(event) {
        const file = event.target.files[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (e) => {
            try {
                const projectData = JSON.parse(e.target.result);

                // Stop current playback
                if (this.isPlaying) {
                    this.togglePlayback();
                }

                // Load project data
                this.patterns = projectData.patterns || [];
                this.numSteps = projectData.numSteps || 16;

                if (projectData.bpm) {
                    Tone.Transport.bpm.value = projectData.bpm;
                    this.dom.bpmSlider.value = projectData.bpm;
                    this.dom.bpmDisplay.textContent = projectData.bpm;
                    this.dom.bpmLive.textContent = projectData.bpm;
                }

                // Recreate synths
                this.patterns.forEach(pattern => {
                    pattern.tracks.forEach(track => {
                        if (track.type === 'drum') {
                            if (track.name === 'Kick') {
                                track.synth = new Tone.MembraneSynth().connect(this.masterBus);
                            } else if (track.name === 'Snare') {
                                track.synth = new Tone.NoiseSynth().connect(this.masterBus);
                            } else if (track.name === 'Hi-Hat') {
                                track.synth = new Tone.MetalSynth({ frequency: 200, envelope: { attack: 0.001, decay: 0.1, release: 0.01 } }).connect(this.masterBus);
                            }
                        } else if (track.type === 'melodic') {
                            if (track.name === 'Bass') {
                                track.synth = new Tone.MonoSynth({ oscillator: { type: 'sawtooth' } }).connect(this.masterBus);
                            } else {
                                track.synth = new Tone.PolySynth(Tone.Synth).connect(this.masterBus);
                            }
                        }
                    });
                });

                // Set first pattern as active
                if (this.patterns.length > 0) {
                    this.setActivePattern(this.patterns[0].id);
                }

                this.dom.stepsSelect.value = this.numSteps;
                this.showModal('Project Loaded', 'Your project has been loaded successfully!');

            } catch (error) {
                console.error('Load failed:', error);
                this.showModal('Load Error', 'Failed to load project file. Please check the file format.');
            }
        };

        reader.readAsText(file);
    }

    getActivePattern() {
        return this.patterns.find(p => p.id === this.activePatternId);
    }

    showWelcomeModal() {
        this.dom.modalOverlay.classList.add('open');
    }

    hideModal() {
        this.dom.modalOverlay.classList.remove('open');
    }

    showModal(title, text) {
        document.getElementById('modal-title').textContent = title;
        document.getElementById('modal-text').textContent = text;
        this.dom.modalOverlay.classList.add('open');

        setTimeout(() => {
            this.hideModal();
        }, 3000);
    }

    animate() {
        requestAnimationFrame(() => this.animate());

        const time = this.clock.getElapsedTime();
        this.materials.background.uniforms.u_time.value = time;

        // Animate 3D objects
        this.scene.children.forEach(child => {
            if (child.userData.rotationSpeed) {
                child.rotation.x += child.userData.rotationSpeed.x;
                child.rotation.y += child.userData.rotationSpeed.y;
                child.rotation.z += child.userData.rotationSpeed.z;

                // Add some audio-reactive movement
                if (this.isPlaying) {
                    const scale = 1 + Math.sin(time * 2) * 0.1;
                    child.scale.setScalar(scale);
                }
            }
        });

        this.renderer.render(this.scene, this.camera);
    }
}

// Initialize the application
