            border-left: 1px solid var(--border-color);
            z-index: 20; display: flex; flex-direction: column;
        }

        #sequencer-dock {
            position: fixed; bottom: 0; left: 0;
            right: var(--controls-width);
            background: var(--sequencer-bg);
            border-top: 1px solid var(--border-color);
            z-index: 15; padding: 15px; overflow-x: auto;
            transition: bottom 0.3s ease;
        }
        #sequencer-dock.piano-open { bottom: var(--piano-roll-height); }

        /* --- Piano Roll --- */
        #piano-roll-dock {
            position: fixed; bottom: 0; left: 0; right: var(--controls-width);
            height: var(--piano-roll-height); background: #080810;
            border-top: 1px solid var(--border-color); z-index: 18;
            display: flex; transform: translateY(100%); transition: transform 0.3s ease;
        }
        #piano-roll-dock.open { transform: translateY(0); }
        #piano-keyboard { flex-shrink: 0; width: 60px; background: #111; overflow-y: scroll; scrollbar-width: none; }
        #piano-keyboard::-webkit-scrollbar { display: none; }
        .piano-key { height: 12px; border: 1px solid #333; font-size: 0.6em; display: flex; align-items: center; justify-content: center; cursor: pointer; }
        .piano-key.black { background: #444; color: #aaa; margin: -6px 0 -6px 20px; height: 12px; position: relative; z-index: 1; }
        .piano-key.white { background: #ddd; color: #222; }
        #piano-grid-wrapper { flex-grow: 1; overflow-x: auto; }
        #piano-grid { display: grid; grid-template-columns: repeat(var(--num-steps, 16), 40px); grid-auto-rows: 12px; }
        .piano-cell { background-color: rgba(255,255,255,0.02); border: 1px solid #222; cursor: pointer; }
        .piano-cell:hover { background-color: rgba(255,255,255,0.1); }
        .piano-cell.note-on { background-color: var(--accent-color); border-color: var(--accent-hover); }

        /* --- Tabs & Main Panel --- */
        .tabs { display: grid; grid-template-columns: repeat(auto-fit, minmax(50px, 1fr)); flex-shrink: 0; border-bottom: 1px solid var(--border-color); }
        .tab-button { padding: 12px 5px; background: transparent; border: none; color: var(--text-color); cursor: pointer; font-weight: bold; font-size: 0.75em; transition: all 0.2s; border-bottom: 3px solid transparent; }
        .tab-button:hover { background-color: rgba(255,255,255,0.1); }
        .tab-button.active { color: var(--accent-color); border-bottom-color: var(--accent-color); }
        .tab-content-wrapper { flex-grow: 1; overflow-y: auto; }
        .tab-content { display: none; padding: 15px; }
        .tab-content.active { display: block; }

        /* --- UI Components --- */
        h1, h2, h4 { color: var(--accent-color); text-align: center; margin: 0 0 15px 0; text-transform: uppercase; letter-spacing: 1px; }
        h4 { margin: 15px 0 10px; text-align: left; }
        fieldset, details { border: 1px solid #444; border-radius: 8px; padding: 10px; margin-bottom: 15px; }
        legend, summary { font-weight: bold; color: var(--accent-color); cursor: pointer; }
        label { display: block; margin: 10px 0 5px; font-size: 0.85em; }
        input[type="range"] { -webkit-appearance: none; appearance: none; width: 100%; height: 5px; background: #333; border-radius: 5px; outline: none; }
        input[type="range"]::-webkit-slider-thumb { -webkit-appearance: none; appearance: none; width: 15px; height: 15px; background: var(--accent-color); cursor: pointer; border-radius: 50%; }
        input[type="range"]::-moz-range-thumb { width: 15px; height: 15px; background: var(--accent-color); cursor: pointer; border-radius: 50%; }
        select, textarea, input[type="text"], input[type="file"] { width: 100%; background: #333; color: var(--text-color); border: 1px solid #555; padding: 8px; border-radius: 5px; }
        textarea { resize: vertical; min-height: 60px; }
        button { background-color: var(--accent-color); color: #000; border: none; padding: 10px 15px; border-radius: 5px; cursor: pointer; width: 100%; font-weight: bold; margin-top: 10px; transition: background-color 0.2s, transform 0.1s; }
        button:hover { background-color: var(--accent-hover); }
        button:active { transform: scale(0.98); }
        button:disabled { background-color: #555; cursor: not-allowed; }
        button.recording { background-color: var(--record-color); color: white; }
        .button-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; }
        .loader { border: 4px solid #f3f3f3; border-radius: 50%; border-top: 4px solid var(--accent-color); width: 20px; height: 20px; animation: spin 2s linear infinite; display: none; margin: 10px auto; }
        @keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }

        /* --- Sequencer & Tracks --- */
        .track { display: flex; align-items: center; gap: 8px; margin-bottom: 8px; }
        .track-header { width: 120px; display: flex; align-items: center; gap: 5px; flex-shrink: 0; }
        .track-label { font-size: 0.9em; font-weight: bold; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; flex-grow: 1; cursor: pointer; }
        .track-label:hover { text-decoration: underline; }
        .clear-track-btn { all: unset; box-sizing: border-box; cursor: pointer; font-size: 0.8em; color: #888; border: 1px solid #555; border-radius: 4px; padding: 2px 5px; line-height: 1; transition: all 0.2s; }
        .clear-track-btn:hover { background: var(--record-color); color: white; border-color: var(--record-color); }
        .steps { display: grid; grid-template-columns: repeat(var(--num-steps, 16), 1fr); gap: 5px; flex-grow: 1;}
        .step { width: 100%; padding-bottom: 100%; height: 0; background: var(--step-off); border-radius: 5px; cursor: pointer; transition: all 0.15s ease; position: relative; border: 1px solid transparent; }
        .step-content { position: absolute; inset: 0; display: flex; align-items: center; justify-content: center; font-size: 0.7em; }
        .step:hover { background-color: rgba(255, 255, 255, 0.2); }
        .step.on { background-color: var(--step-on); }
        .step.visual { background-color: var(--step-visual); }
        .step.active { box-shadow: 0 0 10px var(--step-active), inset 0 0 5px rgba(0,0,0,0.5); transform: scale(1.1); }
        .step.has-plock { border: 1px solid var(--step-plock); }
        .step.drag-over { border: 2px dashed white; }

        /* --- Arranger --- */
        #pattern-clips-container { display: flex; flex-wrap: wrap; gap: 8px; margin-bottom: 10px; }
        .pattern-clip { background: #333; padding: 8px 12px; border-radius: 5px; cursor: grab; transition: all 0.2s; border: 1px solid #555; }
        .pattern-clip.active-pattern { background: var(--accent-color); color: black; font-weight: bold; border-color: var(--accent-hover); }
        #master-track-container { display: grid; grid-template-columns: repeat(8, 1fr); gap: 5px; }
        .master-track-slot { background: var(--step-off); height: 35px; border-radius: 4px; font-size: 0.7em; display: flex; align-items: center; justify-content: center; overflow: hidden; white-space: nowrap; }

        /* --- Modals --- */
        .modal-overlay { display: none; position: fixed; inset: 0; background: rgba(0,0,0,0.7); backdrop-filter: blur(5px); z-index: 199; }
        .modal { display: none; position: fixed; top: 50%; left: 50%; transform: translate(-50%, -50%); background: var(--panel-bg); padding: 20px; border-radius: 10px; z-index: 200; box-shadow: 0 10px 30px rgba(0,0,0,0.5); width: 90%; max-width: 500px; border: 1px solid var(--border-color); }
        .modal.open { display: block; } .modal-overlay.open { display: block; }
        .modal h3 { margin-top: 0; color: var(--accent-color); }
        #note-grid { display: grid; grid-template-columns: repeat(12, 1fr); gap: 5px; max-height: 300px; overflow-y: auto; margin-bottom: 15px; }
        #note-grid button { margin: 0; padding: 8px 4px; font-size: 0.8em; }

        /* --- Responsive --- */
        #mobile-controls-toggle { display: none; }
        @media (max-width: 768px) {
            :root { --controls-width: 100%; --piano-roll-height: 200px; }
            #main-controls-panel { transform: translateX(100%); transition: transform 0.3s ease-in-out; position: fixed; height: 100%; top: 0; right: 0; }
            #main-controls-panel.open { transform: translateX(0); }
            #sequencer-dock, #piano-roll-dock { right: 0; }
            #mobile-controls-toggle { display: block; position: fixed; bottom: 20px; right: 20px; z-index: 50; width: 50px; height: 50px; border-radius: 50%; font-size: 1.5em; padding: 0; }
        }
    </style>
</head>
<body>
    <div id="container"></div>

