                    <div id="kaoss-indicator" style="position: absolute; width: 15px; height: 15px; background: white; border-radius: 50%; top: 50%; left: 50%; transform: translate(-50%, -50%); opacity: 0; pointer-events: none; transition: opacity 0.2s;"></div>
