    <script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>
    <script src="https://cdn.jsdelivr.net/npm/three@0.128.0/examples/js/controls/OrbitControls.js"></script>
    <script src="https://cdnjs.cloudflare.com/ajax/libs/tone/14.7.77/Tone.js"></script>

    <script type="x-shader/x-vertex" id="vertexShader">
        varying vec2 vUv;
        void main() {
            vUv = uv;
            gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
        }
    </script>

    <script type="x-shader/x-fragment" id="generativeFragmentShader">
        uniform vec2 u_resolution;
        uniform float u_time;
        uniform float u_complexity;
        uniform float u_intensity;
        uniform int u_pattern;
        uniform sampler2D u_feedback_texture;
        varying vec2 vUv;
        #define PI 3.14159265359

        float random(vec2 st) { return fract(sin(dot(st.xy, vec2(12.9898, 78.233))) * 43758.5453123); }
        float noise(vec2 st) { vec2 i=floor(st); vec2 f=fract(st); vec2 u=f*f*(3.-2.*f); return mix(mix(random(i),random(i+vec2(1,0)),u.x),mix(random(i+vec2(0,1)),random(i+vec2(1,1)),u.x),u.y); }
        mat2 rotate(float a) { float s=sin(a); float c=cos(a); return mat2(c,-s,s,c); }

        vec3 hsv2rgb(vec3 c) {
            vec4 K = vec4(1.0, 2.0 / 3.0, 1.0 / 3.0, 3.0);
            vec3 p = abs(fract(c.xxx + K.xyz) * 6.0 - K.www);
            return c.z * mix(K.xxx, clamp(p - K.xxx, 0.0, 1.0), c.y);
        }

        vec3 getColor(float value) {
            float hue = fract(u_time * 0.05 + value * 0.1);
            float sat = 0.8;
            float val = clamp(value, 0.0, 1.0);
            return hsv2rgb(vec3(hue, sat, val));
        }

        vec3 pattern_fluid(vec2 st) {
            float v = 0.0; float a = 0.5; st *= 2.0 + u_complexity * 2.0;
            for (int i = 0; i < 7; i++) { v += a * noise(st); st = rotate(0.1) * st; st *= 2.0; a *= 0.5; }
            vec2 q = vec2(v);
            vec2 r = vec2(noise(st + q * u_intensity + u_time * 0.1), noise(st + q * u_intensity + u_time * 0.1));
            float f = noise(st + r);
            return getColor(f);
        }

        float sdBox(vec3 p, vec3 b) { vec3 q = abs(p) - b; return length(max(q,0.0)) + min(max(q.x,max(q.y,q.z)),0.0); }
        vec3 pattern_geo(vec2 st) {
            vec3 ro = vec3(0, 0, -5.0); vec3 rd = normalize(vec3(st - 0.5, 1.0)); float d = 0.0;
            for (int i = 0; i < 64; i++) {
                vec3 p = ro + rd * d;
                p.xy *= rotate(u_time * 0.2 + u_complexity * 2.0); p.xz *= rotate(u_time * 0.1);
                float s = 0.5 + 0.5 * sin(u_time * 0.5); float ds = sdBox(p, vec3(s));
                d += ds * 0.5; if (d > 100.0 || ds < 0.001) break;
            }
            float glow = 1.0 / (d * d * 5.0 + 0.1);
            return getColor(glow * u_intensity);
        }

        vec3 pattern_rd(vec2 st) {
            vec2 texel = 1.0 / u_resolution.xy;
            vec4 n=texture2D(u_feedback_texture,st+vec2(0,1)*texel), e=texture2D(u_feedback_texture,st+vec2(1,0)*texel), s=texture2D(u_feedback_texture,st+vec2(0,-1)*texel), w=texture2D(u_feedback_texture,st+vec2(-1,0)*texel), c=texture2D(u_feedback_texture,st);
            vec4 lap = n + e + s + w - 4.0 * c;
            float feed = mix(0.054, 0.06, u_complexity); float kill = mix(0.06, 0.063, 0.5 + u_intensity * 0.5);
            float A = c.x + (1.0 * lap.x - c.x * c.y * c.y + feed * (1.0 - c.x)) * 1.0;
            float B = c.y + (0.5 * lap.y + c.x * c.y * c.y - (kill + feed) * c.y) * 1.0;
            if (random(st + u_time) > 0.999) B = 1.0;
            return getColor((A - B) * 2.0);
        }

        vec3 pattern_kaleido(vec2 st) {
            vec2 p = st - 0.5;
            float r = length(p);
            float a = atan(p.y, p.x);
            float sides = floor(2.0 + u_complexity * 10.0);
            a = mod(a, PI * 2.0 / sides);
            a = abs(a - PI / sides);
            p = r * vec2(cos(a), sin(a));
            p += 0.5;
            vec3 feedbackColor = texture2D(u_feedback_texture, p).rgb;
            feedbackColor *= 0.97 + u_intensity * 0.02;
            vec3 baseColor = getColor(noise(p * 5.0 + u_time * 0.1));
            return mix(baseColor, feedbackColor, 0.8);
        }

        void main() {
            vec2 st = vUv;
            st.x *= u_resolution.x / u_resolution.y;
            vec3 color = vec3(0.0);
            if (u_pattern == 0)      color = pattern_fluid(st);
            else if (u_pattern == 1) color = pattern_geo(st);
            else if (u_pattern == 2) color = pattern_rd(st);
            else if (u_pattern == 3) color = pattern_kaleido(st);
            gl_FragColor = vec4(color, 1.0);
        }
    </script>

     <script type="x-shader/x-fragment" id="compositeFragmentShader">
        varying vec2 vUv;
        uniform sampler2D u_layer1_texture;
        uniform sampler2D u_image_texture;
        uniform float u_layer2_opacity;
        uniform int u_layer2_blend_mode;

        vec3 blendAdd(vec3 base, vec3 blend) { return min(base + blend, vec3(1.0)); }
        vec3 blendScreen(vec3 base, vec3 blend) { return 1.0 - (1.0 - base) * (1.0 - blend); }
        vec3 blendMultiply(vec3 base, vec3 blend) { return base * blend; }

        void main() {
            vec3 layer1Color = texture2D(u_layer1_texture, vUv).rgb;
            vec3 layer2Color = texture2D(u_image_texture, vUv).rgb;
            vec3 finalColor = layer1Color;
            if (u_layer2_blend_mode == 1) { finalColor = mix(layer1Color, blendAdd(layer1Color, layer2Color), u_layer2_opacity); }
            else if (u_layer2_blend_mode == 2) { finalColor = mix(layer1Color, blendScreen(layer1Color, layer2Color), u_layer2_opacity); }
            else if (u_layer2_blend_mode == 3) { finalColor = mix(layer1Color, blendMultiply(layer1Color, layer2Color), u_layer2_opacity); }
            else { finalColor = mix(layer1Color, layer2Color, u_layer2_opacity); }
            gl_FragColor = vec4(finalColor, 1.0);
        }
    </script>

    <script>
    document.addEventListener('DOMContentLoaded', () => {
