        const GEMINI_API_URL = 'https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash:generateContent?key=';
        const VISUAL_PATTERNS = ["Fluid Noise", "Geometrics", "Reaction-Diffusion", "Kaleidoscope"];
        const CLASSES = { OPEN: 'open', ACTIVE: 'active', ON: 'on', VISUAL: 'visual', HAS_PLOCK: 'has-plock', DRAG_OVER: 'drag-over', RECORDING: 'recording' };

