            manageApiKeyBtn: $('#manage-api-key-btn'), apiKeyModal: $('#api-key-modal'), apiKeyInput: $('#api-key-input'), saveApiKeyBtn: $('#save-api-key-btn'),
            generatePatternBtn: $('#generate-pattern-btn'), aiPatternPrompt: $('#ai-pattern-prompt'), aiPatternLoader: $('#ai-pattern-loader'),
            generateSoundBtn: $('#generate-sound-btn'), aiSynthTarget: $('#ai-synth-target'), aiSoundPrompt: $('#ai-sound-prompt'), aiSoundLoader: $('#ai-sound-loader'),
