            // Arranger
            createPatternBtn: $('#create-pattern-btn'), patternClipsContainer: $('#pattern-clips-container'), masterTrackContainer: $('#master-track-container'),
            // Modals
            noteModal: $('#note-modal'), noteGrid: $('#note-grid'),
            plockModal: $('#plock-modal'), plockParamSelect: $('#plock-param-select'), plockValueSlider: $('#plock-value-slider'), plockValueLabel: $('#plock-value-label'), plockSaveBtn: $('#plock-save-btn'), plockClearBtn: $('#plock-clear-btn'),
            modalOverlay: $('.modal-overlay'), closeModalBtns: $$('.close-modal-btn'), messageModal: $('#message-modal'),
            // Sampling & Recording
            granularSampleInput: $('#granular-sample-input'), recordSampleBtn: $('#record-sample-btn'), addSampleTrackBtn: $('#add-sample-track-btn'),
            recordBtn: $('#record-btn'), recordAudioBtn: $('#record-audio-btn'),
            // Misc
            kaossPad: $('#kaoss-pad'), kaossIndicator: $('#kaoss-indicator'), modMatrixContainer: $('#mod-matrix-container'), midiInputSelect: $('#midi-input-select'),
            projectFileInput: $('#project-file-input'), loadProjectBtn: $('#load-project-btn'), saveProjectBtn: $('#save-project-btn'),
        };

        // --- AI MANAGER ---
        const AIManager = {
            apiKey: sessionStorage.getItem('geminiApiKey') || '',
            async callApi(prompt) {
                if (!this.apiKey) {
                    showMessage('API Key Missing', 'Please set your Gemini API key in the AI tab.');
                    openModal(DOM.apiKeyModal);
                    return null;
                }
                const url = GEMINI_API_URL + this.apiKey;
                const payload = { contents: [{ role: "user", parts: [{ text: prompt }] }] };

                try {
                    const response = await fetch(url, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
                    if (!response.ok) { const errorBody = await response.json(); throw new Error(`API Error: ${errorBody.error?.message || response.statusText}`); }
                    const result = await response.json();

                    if (!result.candidates?.[0]?.content?.parts?.[0]?.text) throw new Error("No content returned from AI.");
                    const textContent = result.candidates[0].content.parts[0].text;
                    const jsonMatch = textContent.match(/```json\n([\s\S]*?)\n```/);
                    if (jsonMatch) return JSON.parse(jsonMatch[1]);
                    return textContent;

                } catch (error) {
                    console.error("AI API call failed:", error);
                    showMessage('AI Error', `Failed to get a response. Check console. Error: ${error.message}`);
                    return null;
                }
            },
        };

        // --- VISUALS ENGINE (3D + 2D Shader) ---
        let scene, camera, renderer, clock, threeJSContainer;
        let generativeMaterial, compositeMaterial, backgroundScene, backgroundCamera, planeMesh;
        let generativeRenderTarget, prevFrameTexture, currentFrameTexture;
        let imageTextureLoader, imageTexture;

        function initVisuals() {
            threeJSContainer = $('#container');
            scene = new THREE.Scene();
            clock = new THREE.Clock();
            camera = new THREE.PerspectiveCamera(75, threeJSContainer.clientWidth / threeJSContainer.clientHeight, 0.1, 1000);
            camera.position.z = 5;
            renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
            renderer.autoClear = false;
            threeJSContainer.appendChild(renderer.domElement);

            // 2D Background Scene
            backgroundScene = new THREE.Scene();
            backgroundCamera = new THREE.OrthographicCamera(-1, 1, 1, -1, 0, 1);
            const targetOptions = { minFilter: THREE.LinearFilter, magFilter: THREE.NearestFilter, format: THREE.RGBAFormat, type: THREE.FloatType };
            prevFrameTexture = new THREE.WebGLRenderTarget(window.innerWidth, window.innerHeight, targetOptions);
            currentFrameTexture = new THREE.WebGLRenderTarget(window.innerWidth, window.innerHeight, targetOptions);

            imageTextureLoader = new THREE.TextureLoader();
            imageTexture = imageTextureLoader.load('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); // 1x1 black pixel

            generativeMaterial = new THREE.ShaderMaterial({
                uniforms: {
                    u_time: { value: 0.0 }, u_resolution: { value: new THREE.Vector2() }, u_pattern: { value: 0 },
                    u_complexity: { value: 0.6 }, u_intensity: { value: 1.0 }, u_feedback_texture: { value: prevFrameTexture.texture }
                },
                vertexShader: $('#vertexShader').textContent, fragmentShader: $('#generativeFragmentShader').textContent
            });

            compositeMaterial = new THREE.ShaderMaterial({
                uniforms: {
                    u_layer1_texture: { value: currentFrameTexture.texture }, u_image_texture: { value: imageTexture },
                    u_layer2_opacity: { value: 0.0 }, u_layer2_blend_mode: { value: 0 }
                },
                vertexShader: $('#vertexShader').textContent, fragmentShader: $('#compositeFragmentShader').textContent
            });

            planeMesh = new THREE.Mesh(new THREE.PlaneGeometry(2, 2), compositeMaterial);
            backgroundScene.add(planeMesh);
            DOM.visualPatternSelect.innerHTML = VISUAL_PATTERNS.map((name, i) => `<option value="${i}">${name}</option>`).join('');

            window.addEventListener('resize', onWindowResize, false);
            onWindowResize();
        }
        function onWindowResize() {
            const controlsWidth = document.body.clientWidth > 768 ? parseInt(getComputedStyle(document.documentElement).getPropertyValue('--controls-width')) : 0;
            const viewWidth = window.innerWidth - controlsWidth;
            const viewHeight = window.innerHeight;
            camera.aspect = viewWidth / viewHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(viewWidth, viewHeight);
            generativeMaterial.uniforms.u_resolution.value.set(viewWidth, viewHeight);
            prevFrameTexture.setSize(viewWidth, viewHeight);
            currentFrameTexture.setSize(viewWidth, viewHeight);
        }

        // --- TONE.JS AUDIO ENGINE ---
        let masterFilter, masterDelay, masterReverb;
        let transportLoop;
        async function setupAudio() {
            await Tone.start();
            masterReverb = new Tone.Reverb(2).toDestination();
            masterDelay = new Tone.FeedbackDelay(0.2, 0.5).connect(masterReverb);
            masterFilter = new Tone.Filter(20000, "lowpass").connect(masterDelay);

            Tone.Transport.bpm.value = 120;
            state.audioReady = true;
            DOM.playToggleBtn.disabled = false;
            DOM.playToggleBtn.textContent = 'Play';

            state.mic = new Tone.UserMedia();
            state.sampleRecorder = new Tone.Recorder();
            state.mic.connect(state.sampleRecorder);

            state.audioRecorder = new Tone.Recorder();
            masterFilter.connect(state.audioRecorder);

            createNewPattern();
            buildModMatrixUI();
            setupMIDI();
        }

        function createNewPattern(id = null, name = null) {
            const newId = id || Date.now().toString();
            const newPattern = {
                id: newId, name: name || `Ptn ${state.patterns.length + 1}`,
                tracks: [
                    { name: 'VIS', type: 'control', data: []},
                    { name: 'Kick', type: 'drum', synthType: 'MembraneSynth', data: [] },
                    { name: 'Snare', type: 'drum', synthType: 'NoiseSynth', data: [] },
                    { name: 'Hat', type: 'drum', synthType: 'MetalSynth', data: [] },
                    { name: 'Bass', type: 'melodic', synthType: 'MonoSynth', data: [] },
                    { name: 'Poly', type: 'polyphonic', synthType: 'PolySynth', data: [] },
                    { name: 'Granular', type: 'sampler', synthType: 'GrainPlayer', data: [] },
                ]
            };
            newPattern.tracks.forEach(track => {
                track.data = Array.from({ length: 64 }, () => ({ active: 0, note: "C3", pLocks: {}, visualClipIndex: null }));
            });
            state.patterns.push(newPattern);
            if (!state.activePatternId) {
                setActivePattern(newId);
            }
        }

        function getSynthForTrack(track) {
            switch (track.synthType) {
                case 'MembraneSynth': return new Tone.MembraneSynth().connect(masterFilter);
                case 'NoiseSynth': return new Tone.NoiseSynth().connect(masterFilter);
                case 'MetalSynth': return new Tone.MetalSynth({frequency: 200, envelope: {attack: 0.001, decay: 0.1, release: 0.01}, harmonicity: 5.1, modulationIndex: 32, resonance: 4000, octaves: 1.5}).connect(masterFilter);
                case 'MonoSynth': return new Tone.MonoSynth({oscillator: {type: 'sawtooth'}, envelope: {attack: 0.01, decay: 0.2, sustain: 0.2, release: 0.1}, filterEnvelope: {attack: 0.01, decay: 0.1, sustain: 0.1, release: 0.1, baseFrequency: 100, octaves: 4}}).connect(masterFilter);
                case 'PolySynth': return new Tone.PolySynth(Tone.Synth).connect(masterFilter);
                case 'GrainPlayer': return new Tone.GrainPlayer({ url: "", loop: true, grainSize: 0.2, overlap: 0.1 }).connect(masterFilter);
                case 'FMSynth': return new Tone.FMSynth().connect(masterFilter);
                case 'AMSynth': return new Tone.AMSynth().connect(masterFilter);
                case 'PluckSynth': return new Tone.PluckSynth().connect(masterFilter);
                default: return null;
            }
        }


        function setActivePattern(patternId) {
            if (transportLoop) { transportLoop.dispose(); transportLoop = null; }

            // Dispose old synths
            const oldPattern = state.patterns.find(p => p.id === state.activePatternId);
            if (oldPattern) { oldPattern.tracks.forEach(t => t.synth?.dispose()); }

            state.activePatternId = patternId;
            const activePattern = state.patterns.find(p => p.id === patternId);
            if (!activePattern) return;

            // Create new synths
            activePattern.tracks.forEach(track => { track.synth = getSynthForTrack(track); });

            transportLoop = new Tone.Sequence((time, step) => {
                const arrangementPatternId = state.arrangement[Math.floor(step / state.numSteps) % state.arrangement.length];
                const patternToPlay = arrangementPatternId ? state.patterns.find(p => p.id === arrangementPatternId) : activePattern;
                const currentPatternStep = step % state.numSteps;

                if (patternToPlay) {
                    patternToPlay.tracks.forEach(track => {
                        const stepData = track.data[currentPatternStep];
                        if (!track.synth && track.type !== 'control') track.synth = getSynthForTrack(track); // safety check

                        // Apply P-Locks before triggering
                        if (track.synth && stepData.pLocks) {
                            for (const param in stepData.pLocks) { setSynthParam(track.synth, param, stepData.pLocks[param]); }
                        }

                        if (stepData.active && track.synth) {
                            if (track.synthType === 'NoiseSynth') track.synth.triggerAttackRelease("8n", time);
                            else if (track.type === 'drum') track.synth.triggerAttackRelease("C1", "8n", time);
                            else if (track.type === 'melodic' || track.type === 'polyphonic') track.synth.triggerAttackRelease(stepData.note, "8n", time);
                            else if (track.type === 'sampler' && track.synth.loaded) track.synth.start(time);
                        }

                        const visTrack = patternToPlay.tracks.find(t=>t.name==='VIS');
                        if(visTrack && visTrack.data[currentPatternStep].visualClipIndex !== null){
                             applyVisualClip(state.visualClips[visTrack.data[currentPatternStep].visualClipIndex]);
                        }
                    });
                }
                Tone.Draw.schedule(() => highlightStep(currentPatternStep), time);
            }, Array.from({ length: 256 }, (_, i) => i), "16n").start(0);

            buildSequencerUI();
            buildSynthControlsUI();
            buildArrangerUI();
            updateAiSynthTargetDropdown();
            if(state.isPianoRollOpen) buildPianoRollUI();
        }

        // --- UI & WORKFLOW ---
        function buildSequencerUI() {
            const activePattern = state.patterns.find(p => p.id === state.activePatternId);
            if (!activePattern) { DOM.sequencerContainer.innerHTML = ''; return; }
            DOM.sequencerContainer.innerHTML = '';
            DOM.sequencerContainer.style.setProperty('--num-steps', state.numSteps);
            activePattern.tracks.forEach((track, trackIndex) => {
                const trackEl = document.createElement('div');
                trackEl.className = 'track';
                trackEl.dataset.trackIndex = trackIndex;
                let stepsHTML = '';
                for(let i=0; i < state.numSteps; i++) {
                    const stepData = track.data[i];
                    let classes = 'step';
                    const hasData = stepData.active || (track.name === 'VIS' && stepData.visualClipIndex !== null);
                    if(hasData) classes += ' on';
                    if(track.name === 'VIS' && hasData) classes += ' visual';
                    if (stepData.pLocks && Object.keys(stepData.pLocks).length > 0) classes += ' has-plock';
                    const noteLabel = (track.type === 'melodic' || track.type === 'polyphonic') && stepData.active ? stepData.note.replace('#', '♯') : '';
                    stepsHTML += `<div class="${classes}" data-step-index="${i}"><div class="step-content">${noteLabel}</div></div>`;
                }
                trackEl.innerHTML = `<div class="track-header"><span class="track-label" title="${track.name}">${track.name}</span><button class="clear-track-btn" title="Clear Pattern">[ C ]</button></div><div class="steps">${stepsHTML}</div>`;
                DOM.sequencerContainer.appendChild(trackEl);
            });
        }

        function highlightStep(step) {
            state.currentStep = step;
            $$('.step.active').forEach(el => el.classList.remove(CLASSES.ACTIVE));
            $$(`.step[data-step-index='${step}']`).forEach(el => el.classList.add(CLASSES.ACTIVE));
        }

        function buildSynthControlsUI() {
             const activePattern = state.patterns.find(p => p.id === state.activePatternId);
             if (!activePattern) return;
             DOM.synthControlsContainer.innerHTML = '';
             activePattern.tracks.filter(t => t.synth).forEach(track => {
                 const details = document.createElement('details');
                 details.open = track.name === 'Bass' || track.name === 'Poly';
                 details.innerHTML = `<summary>${track.name}</summary>`;
                 const controls = getAdvancedControlsForSynth(track);
                 for (const param in controls) {
                     const control = controls[param];
                     const id = `${track.name}-${param.replace(/\./g, '-')}`;
                     const valSpan = document.createElement('span'); valSpan.textContent = ` (${parseFloat(control.value).toFixed(2)})`;
                     const label = document.createElement('label'); label.htmlFor = id; label.textContent = param; label.appendChild(valSpan);
                     const input = document.createElement('input');
                     input.type = 'range'; input.id = id; input.min = control.min; input.max = control.max; input.step = control.step; input.value = control.value;
                     input.dataset.paramPath = param; input.dataset.trackName = track.name;
                     input.addEventListener('input', (e) => {
                         const val = parseFloat(e.target.value);
                         setSynthParam(track.synth, param, val);
                         valSpan.textContent = ` (${val.toFixed(2)})`;
                     });
                     details.append(label, input);
                 }
                 DOM.synthControlsContainer.appendChild(details);
             });
        }

        function buildPianoRollUI() {
            if (state.activePianoRollTrackIndex === null) return;
            const activePattern = state.patterns.find(p => p.id === state.activePatternId);
            const track = activePattern.tracks[state.activePianoRollTrackIndex];
            if (!track || (track.type !== 'melodic' && track.type !== 'polyphonic')) { closePianoRoll(); return; }
            DOM.pianoKeyboard.innerHTML = '';
            DOM.pianoGrid.innerHTML = '';
            DOM.pianoGrid.style.setProperty('--num-steps', state.numSteps);
            const allNotes = [];
            OCTAVES.forEach(octave => {
                NOTES.slice().reverse().forEach(note => {
                    const noteName = `${note}${octave}`;
                    allNotes.push(noteName);
                    const keyEl = document.createElement('div');
                    keyEl.className = `piano-key ${note.includes('#') ? 'black' : 'white'}`;
                    keyEl.dataset.note = noteName;
                    keyEl.textContent = noteName;
                    DOM.pianoKeyboard.appendChild(keyEl);
                });
            });
            allNotes.forEach(note => {
                for (let i = 0; i < state.numSteps; i++) {
                    const cellEl = document.createElement('div');
                    cellEl.className = 'piano-cell';
                    cellEl.dataset.note = note;
                    cellEl.dataset.step = i;
                    const stepData = track.data[i];
                    if (stepData.active && stepData.note === note) {
                        cellEl.classList.add('note-on');
                    }
                    DOM.pianoGrid.appendChild(cellEl);
                }
            });
        }
        function openPianoRoll(trackIndex) {
            state.activePianoRollTrackIndex = trackIndex;
            state.isPianoRollOpen = true;
            DOM.pianoRollDock.classList.add(CLASSES.OPEN);
            DOM.sequencerDock.classList.add('piano-open');
            buildPianoRollUI();
        }
        function closePianoRoll() {
            state.isPianoRollOpen = false;
            DOM.pianoRollDock.classList.remove(CLASSES.OPEN);
            DOM.sequencerDock.classList.remove('piano-open');
        }

        function buildArrangerUI() {
            DOM.patternClipsContainer.innerHTML = '';
            state.patterns.forEach(pattern => {
                const clipEl = document.createElement('div');
                clipEl.className = 'pattern-clip';
                clipEl.classList.toggle('active-pattern', pattern.id === state.activePatternId);
                clipEl.textContent = pattern.name; clipEl.dataset.patternId = pattern.id; clipEl.draggable = true;
                clipEl.addEventListener('dragstart', e => e.dataTransfer.setData('pattern/id', pattern.id));
                clipEl.addEventListener('click', () => setActivePattern(pattern.id));
                DOM.patternClipsContainer.appendChild(clipEl);
            });
            DOM.masterTrackContainer.innerHTML = '';
            state.arrangement.forEach((patternId, index) => {
                const slotEl = document.createElement('div');
                slotEl.className = 'master-track-slot'; slotEl.dataset.index = index;
                if (patternId !== null) {
                    const pattern = state.patterns.find(p => p.id === patternId);
                    slotEl.textContent = pattern ? pattern.name : '??';
                    slotEl.style.backgroundColor = 'var(--step-on)';
                }
                slotEl.addEventListener('contextmenu', e => { e.preventDefault(); state.arrangement[index] = null; buildArrangerUI(); });
                DOM.masterTrackContainer.appendChild(slotEl);
            });
        }

        function buildModMatrixUI() {}

        function openModal(modal) { DOM.modalOverlay.classList.add(CLASSES.OPEN); modal.classList.add(CLASSES.OPEN); }
        function closeModal() { $$('.modal.open').forEach(m => m.classList.remove(CLASSES.OPEN)); DOM.modalOverlay.classList.remove(CLASSES.OPEN); }
        function showMessage(title, text) { $('#message-title').textContent = title; $('#message-text').textContent = text; openModal($('#message-modal')); }

        function updateAiSynthTargetDropdown() {
            const activePattern = state.patterns.find(p => p.id === state.activePatternId);
            if (!activePattern) { DOM.aiSynthTarget.innerHTML = ''; return; }
            DOM.aiSynthTarget.innerHTML = '';
            activePattern.tracks.filter(t => t.synth).forEach((track) => {
                const option = document.createElement('option');
                option.value = track.name; option.textContent = track.name;
                DOM.aiSynthTarget.appendChild(option);
            });
        }

        function getAdvancedControlsForSynth(track) {
            const synth = track.synth;
            if (!synth) return {};
            switch (track.synthType) {
                case 'MembraneSynth': return { 'envelope.decay': { min: 0.01, max: 0.5, step: 0.01, value: synth.envelope.decay } };
                case 'NoiseSynth': return { 'envelope.decay': { min: 0.01, max: 0.3, step: 0.01, value: synth.envelope.decay } };
                case 'MonoSynth': return { 'filter.frequency': { min: 20, max: 10000, step: 1, value: synth.filter.frequency.value }, 'filter.Q': { min: 0.1, max: 10, step: 0.1, value: synth.filter.Q.value } };
                case 'PolySynth': return { 'envelope.attack': { min: 0.01, max: 1, step: 0.01, value: synth.get().envelope.attack }, 'envelope.release': { min: 0.1, max: 4, step: 0.01, value: synth.get().envelope.release } };
                case 'FMSynth': return { 'harmonicity': { min: 0.1, max: 10, step: 0.1, value: synth.harmonicity.value }, 'modulationIndex': { min: 1, max: 100, step: 1, value: synth.modulationIndex.value } };
                case 'AMSynth': return { 'harmonicity': { min: 0.1, max: 10, step: 0.1, value: synth.harmonicity.value } };
                case 'PluckSynth': return { 'resonance': { min: 0.8, max: 0.99, step: 0.01, value: synth.resonance.value } };
                case 'GrainPlayer': return { 'detune': { min: -1200, max: 1200, step: 1, value: synth.detune }, 'grainSize': { min: 0.01, max: 0.5, step: 0.01, value: synth.grainSize }, 'overlap': { min: 0, max: 0.5, step: 0.01, value: synth.overlap } };
                default: return {};
            }
        }

        function setSynthParam(synth, paramPath, value) {
            try {
                const parts = paramPath.split('.'); let target = synth;
                if (synth instanceof Tone.PolySynth) { const props = {}; parts.reduce((o, k, i) => o[k] = parts.length - 1 === i ? value : o[k] || {}, props); synth.set(props); return; }
                for (let i = 0; i < parts.length - 1; i++) { target = target[parts[i]]; }
                const finalProp = parts[parts.length - 1];
                if (target[finalProp] && typeof target[finalProp].value !== 'undefined') { target[finalProp].value = value; } else { target[finalProp] = value; }
